const document: HandbookDocumentContent = {
  navHtml: "<div class=\"nav-brand\">CAREER · FRONTEND</div>\n  <div class=\"nav-title\">프론트엔드 · JS TS 면접</div>\n  <a href=\"#bundle-index\"><span class=\"code\">INDEX</span>학습 로드맵</a>\n  <a href=\"#career-readiness-gate\"><span class=\"code\">GATE</span>답변 준비도</a>\n  <a href=\"#career-answer-rubric\"><span class=\"code\">RUBRIC</span>답변 품질</a>\n  <a href=\"#career-pressure-loop\"><span class=\"code\">LOOP</span>압박 대응</a>\n  <a href=\"#career-evidence-packet\"><span class=\"code\">EVIDENCE</span>증거 패킷</a>\n  <a href=\"#career-final-drill\"><span class=\"code\">DRILL</span>최종 점검</a>\n  <a href=\"#doc-feinterview\"><span class=\"code\">DOC</span>프론트엔드 면접</a>\n  <a href=\"#doc-jsts\"><span class=\"code\">DOC</span>JavaScript·TypeScript 면접</a>\n  <a href=\"#doc-personalfe\"><span class=\"code\">DOC</span>프론트엔드 개발자 대응</a>\n  <a href=\"#doc-feinterview\"><span class=\"code\">PART</span>프론트엔드 면접</a>\n<a href=\"#feinterview-q0\"><span class=\"code\">FE-00</span>답변 원칙</a>\n  <a href=\"#feinterview-q1\"><span class=\"code\">FE-01</span>브라우저 렌더링</a>\n  <a href=\"#feinterview-q2\"><span class=\"code\">FE-02</span>React 렌더링 최적화</a>\n  <a href=\"#feinterview-q3\"><span class=\"code\">FE-03</span>상태관리 설계</a>\n  <a href=\"#feinterview-q4\"><span class=\"code\">FE-04</span>렌더링 전략</a>\n  <a href=\"#feinterview-q5\"><span class=\"code\">FE-05</span>웹 성능</a>\n  <a href=\"#feinterview-q6\"><span class=\"code\">FE-06</span>접근성</a>\n  <a href=\"#feinterview-q7\"><span class=\"code\">FE-07</span>프론트엔드 보안</a>\n  <a href=\"#feinterview-q8\"><span class=\"code\">FE-08</span>테스트 전략</a>\n  <a href=\"#feinterview-q9\"><span class=\"code\">FE-09</span>서버 상태 분리</a>\n  <a href=\"#feinterview-q10\"><span class=\"code\">FE-10</span>Hydration mismatch</a>\n  <a href=\"#feinterview-q11\"><span class=\"code\">FE-11</span>번들 최적화</a>\n  <a href=\"#feinterview-q12\"><span class=\"code\">FE-12</span>디자인 시스템</a>\n  <a href=\"#feinterview-q13\"><span class=\"code\">FE-13</span>대용량 Grid</a>\n  <a href=\"#feinterview-q14\"><span class=\"code\">FE-14</span>Canvas·SVG·DOM</a>\n  <a href=\"#feinterview-q15\"><span class=\"code\">FE-15</span>장애 디버깅</a>\n  <a href=\"#feinterview-q16\"><span class=\"code\">FE-16</span>핵심 질문 20선</a>\n  <a href=\"#feinterview-react-concurrent-ssr-drill\"><span class=\"code\">FE-D1</span>React Concurrent SSR Drill</a>\n  <a href=\"#feinterview-frontend-security-cache-drill\"><span class=\"code\">FE-D2</span>Security Cache Drill</a>\n  <a href=\"#feinterview-frontend-causal-model\"><span class=\"code\">FE-D3</span>개념 인과관계</a>\n  <a href=\"#feinterview-frontend-expert-rendering-model\"><span class=\"code\">FE-D4</span>전문가 렌더링 모델</a>\n  <a href=\"#feinterview-frontend-deep-answer-upgrade\"><span class=\"code\">FE-D5</span>Deep Answer Model</a>\n  <a href=\"#feinterview-frontend-project-evidence-answer-lab\"><span class=\"code\">FE-D6</span>Evidence Answer Lab</a>\n  <a href=\"#doc-jsts\"><span class=\"code\">PART</span>JavaScript·TypeScript 면접</a>\n<a href=\"#jsts-q1\"><span class=\"code\">JT-01</span>실행 컨텍스트</a>\n  <a href=\"#jsts-q2\"><span class=\"code\">JT-02</span>클로저와 스코프</a>\n  <a href=\"#jsts-q3\"><span class=\"code\">JT-03</span>프로토타입과 this</a>\n  <a href=\"#jsts-q4\"><span class=\"code\">JT-04</span>이벤트 루프</a>\n  <a href=\"#jsts-q5\"><span class=\"code\">JT-05</span>Promise와 async</a>\n  <a href=\"#jsts-q6\"><span class=\"code\">JT-06</span>TypeScript 타입 모델</a>\n  <a href=\"#jsts-q7\"><span class=\"code\">JT-07</span>Generics와 타입 좁히기</a>\n  <a href=\"#jsts-q8\"><span class=\"code\">JT-08</span>답변 비교</a>\n  <a href=\"#jsts-q9\"><span class=\"code\">JT-09</span>런타임 실패 지도</a>\n  <a href=\"#jsts-q10\"><span class=\"code\">JT-10</span>타입 안전 경계</a>\n  <a href=\"#jsts-typescript-advanced-boundary\"><span class=\"code\">JT-D1</span>TypeScript Advanced Boundary</a>\n  <a href=\"#doc-personalfe\"><span class=\"code\">PART</span>프론트엔드 개발자 대응</a>\n<a href=\"#personalfe-ch1\"><span class=\"code\">FE-PER-00</span>성장 서사</a>\n  <a href=\"#personalfe-ch2\"><span class=\"code\">FE-PER-01</span>핵심 강점</a>\n  <a href=\"#personalfe-ch3\"><span class=\"code\">FE-PER-02</span>대표 답변</a>\n  <a href=\"#personalfe-ch4\"><span class=\"code\">FE-PER-03</span>압박 질문</a>\n  <a href=\"#personalfe-ch5\"><span class=\"code\">FE-PER-04</span>포트폴리오 문장</a>\n  <a href=\"#personalfe-ch6\"><span class=\"code\">FE-PER-05</span>대체 증거</a>\n  <a href=\"#personalfe-ch7\"><span class=\"code\">FE-PER-06</span>심화 드릴 연결</a>",
  mainHtml: "<header class=\"hero\">\n  <div class=\"hero-serial\">\n    <span>DOC : CAREER-FRONTEND-INTERVIEW</span>\n    <span>SCOPE : FRONTEND · JAVASCRIPT · TYPESCRIPT · POSITIONING</span>\n    <span>LANG : KO</span>\n  </div>\n  <h1>프론트엔드와 JavaScript·TypeScript 면접</h1>\n  <p class=\"hero-sub\">프론트엔드 면접, JavaScript·TypeScript 면접, 프론트엔드 개발자 대응을 통합했습니다.</p>\n  <div class=\"hero-meta\">CURATED INTERVIEW PATH · SOURCES : 3 DOCUMENTS · UPDATED 2026-06</div>\n</header>\n\n<section id=\"bundle-index\">\n<div class=\"ch-head\"><span class=\"ch-code\">INDEX</span><h2>학습 로드맵</h2></div>\n<p class=\"lede\">이 문서는 아래 원문을 면접 학습 흐름에 맞게 이어 읽도록 구성했습니다. 각 파트는 개념 이해, 압박 질문, 답변 근거를 확인하는 기준점으로 사용합니다.</p>\n<ul><li>프론트엔드 면접</li><li>JavaScript·TypeScript 면접</li><li>프론트엔드 개발자 대응</li></ul>\n</section>\n\n<section id=\"career-readiness-gate\">\n<div class=\"ch-head\"><span class=\"ch-code\">GATE</span><h2>CAREER READINESS GATE</h2></div>\n<p class=\"lede\"><strong>프론트엔드·JS/TS 답변 게이트</strong>는 이 문서를 읽은 뒤 실제 면접에서 바로 말할 수 있어야 하는 산출물 기준입니다. 목표는 더 많이 읽는 것이 아니라, 질문을 받았을 때 30초 결론과 90초 확장을 증거와 함께 말하는 상태를 만드는 것입니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">프론트엔드·JS/TS 답변 게이트</span>\n브라우저, React, TypeScript, 성능, 보안을 기능 구현 경험이 아니라 사용자 영향과 측정 근거로 설명한다.\n</div>\n<table>\n<tr><th>준비 결과</th><th>면접에서 보여야 하는 신호</th><th>미달 신호</th></tr>\n<tr><td>30초 결론</td><td>첫 문장에서 판단 기준과 결론이 나온다.</td><td>배경 설명이 길고 질문의 핵심을 늦게 잡는다.</td></tr>\n<tr><td>90초 확장</td><td>대안, trade-off, 실패 모드, 검증 증거가 이어진다.</td><td>장점만 말하고 깨지는 조건을 말하지 못한다.</td></tr>\n<tr><td>압박 꼬리질문</td><td>모르는 범위와 직접 경험 범위를 분리한 뒤 확인 방법을 말한다.</td><td>직접 하지 않은 일을 경험처럼 포장한다.</td></tr>\n</table>\n<ul><li>렌더링 병목을 state 범위, context, key, network, bundle 중 어디서 찾을지 말한다.</li><li>TypeScript 안전성을 any 회피가 아니라 API 계약, unknown narrowing, discriminated union으로 설명한다.</li><li>프론트 보안과 캐시 문제를 XSS, token storage, CORS, cache invalidation, CSP 증거로 연결한다.</li></ul>\n</section>\n\n<section id=\"career-answer-rubric\">\n<div class=\"ch-head\"><span class=\"ch-code\">RUBRIC</span><h2>ANSWER QUALITY RUBRIC</h2></div>\n<p class=\"lede\">답변 품질은 유창함이 아니라 검증 가능성으로 판단합니다. 아래 기준으로 녹음 답변을 채점하고, 약한 답변은 결론, 근거, 증거 순서로 다시 작성합니다.</p>\n<table>\n<tr><th>등급</th><th>답변 상태</th><th>보정 기준</th></tr>\n<tr><td>S</td><td>결론, 기준, trade-off, 실패 모드, 검증 증거, 본인 기여가 모두 분리된다.</td><td>압박 질문 2개를 붙여도 같은 경계와 증거를 유지한다.</td></tr>\n<tr><td>A</td><td>핵심 개념과 실무 예시는 좋지만 수치나 산출물 증거가 일부 비어 있다.</td><td>PR·ADR·지표·장애기록·QA ticket 중 최소 2개를 붙인다.</td></tr>\n<tr><td>B</td><td>개념 설명은 가능하지만 경험, 대안, 실패 조건이 약하다.</td><td>직접 경험, 일부 참여, 설계 지식을 문장 안에서 분리한다.</td></tr>\n<tr><td>C</td><td>기술명과 기능 목록 중심이고 면접관이 기여도와 판단 기준을 확인하기 어렵다.</td><td>질문을 다시 정의하고 30초 결론부터 재작성한다.</td></tr>\n</table>\n</section>\n\n<section id=\"career-pressure-loop\">\n<div class=\"ch-head\"><span class=\"ch-code\">LOOP</span><h2>PRESSURE RESPONSE LOOP</h2></div>\n<p class=\"lede\">압박 질문은 틀리게 만들기 위한 질문이 아니라 답변의 경계와 증거를 확인하는 질문입니다. 당황했을 때는 답변을 확장하지 말고 구조를 되찾습니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">PRESSURE RESPONSE LOOP</span>\n1. 질문을 한 문장으로 재정의한다<br>\n2. 직접 경험 / 일부 경험 / 설계 지식을 분리한다<br>\n3. 판단 기준 2개만 말한다<br>\n4. 증거 하나와 실패 모드 하나를 붙인다<br>\n5. 남은 불확실성은 검증 계획으로 닫는다\n</div>\n<table>\n<tr><th>압박 질문</th><th>복구 답변</th><th>피해야 할 방향</th></tr>\n<tr><td>React.memo를 썼다는 말 말고 실제로 무엇이 빨라졌나요?</td><td>측정 기준, 병목 위치, 선택한 최적화, 버린 대안, 전후 증거 순서로 답변을 복구한다.</td><td>질문을 피하려고 일반론을 길게 늘리는 것</td></tr>\n<tr><td>그건 본인이 한 일인가요?</td><td>본인 결정, 팀 결정, 외부 제약을 분리하고 본인이 소유한 판단만 말한다.</td><td>팀 성과 전체를 개인 성과처럼 말하는 것</td></tr>\n<tr><td>수치나 증거가 없으면 어떻게 확인하나요?</td><td>정량 지표가 없었던 한계를 인정하고, 재현 절차·QA ticket·before/after·PR diff 같은 대체 증거를 제시한다.</td><td>좋아졌다고만 말하는 것</td></tr>\n</table>\n</section>\n\n<section id=\"career-evidence-packet\">\n<div class=\"ch-head\"><span class=\"ch-code\">EVIDENCE</span><h2>EVIDENCE PACKET</h2></div>\n<p class=\"lede\">면접 답변은 기억이 아니라 증거로 보강합니다. 각 문서에서 최소 하나의 대표 답변을 만들고, 아래 산출물을 붙여 실제 경험과 설계 지식의 경계를 명확히 합니다.</p>\n<table>\n<tr><th>증거 묶음</th><th>준비할 항목</th><th>면접에서 쓰는 방식</th></tr>\n<tr><td>핵심 산출물</td><td>Profiler 캡처, Network waterfall, bundle 분석, PR·ADR·지표·장애기록·QA ticket</td><td>주장 뒤에 바로 붙일 수 있는 근거로 정리한다.</td></tr>\n<tr><td>공통 증거</td><td>PR·ADR·지표·장애기록·QA ticket</td><td>기술 판단, 협업 합의, 결과 확인을 한 번에 보여준다.</td></tr>\n<tr><td>답변 카드</td><td>질문, 30초 결론, 90초 확장, 압박 꼬리질문, 위험 표현, 대체 문장</td><td>면접 전날 같은 질문을 다시 말하며 품질을 점검한다.</td></tr>\n</table>\n</section>\n\n<section id=\"career-final-drill\">\n<div class=\"ch-head\"><span class=\"ch-code\">DRILL</span><h2>FINAL 10 MINUTE DRILL</h2></div>\n<p class=\"lede\">면접 직전에는 새 내용을 추가하지 않습니다. 이미 준비한 답변의 결론, 경계, 증거만 빠르게 복구합니다.</p>\n<table>\n<tr><th>시간</th><th>할 일</th><th>완료 기준</th></tr>\n<tr><td>0-3분</td><td>프론트엔드·JS/TS 답변 게이트 질문 하나를 30초 결론으로 말한다.</td><td>첫 문장에 결론과 판단 기준이 있다.</td></tr>\n<tr><td>3-6분</td><td>같은 질문을 90초 확장으로 말한다.</td><td>대안, trade-off, 실패 모드, 증거가 포함된다.</td></tr>\n<tr><td>6-8분</td><td>압박 꼬리질문 하나를 붙여 답변을 복구한다.</td><td>모르는 범위를 숨기지 않고 확인 방법으로 닫는다.</td></tr>\n<tr><td>8-10분</td><td>DANGEROUS PHRASES를 제거하고 대체 문장으로 바꾼다.</td><td>추상 표현 없이 본인 기여와 증거가 남는다.</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">DANGEROUS PHRASES</span>\n<p>“많이 해봤습니다”, “대충 알고 있습니다”, “그냥 최적화했습니다”, “팀에서 처리했습니다”처럼 범위와 증거가 없는 표현은 약하게 들립니다. “제가 소유한 결정은 A이고, B 제약 때문에 C를 선택했으며, 결과는 D 증거로 확인했습니다”로 바꿉니다.</p>\n</div>\n</section>\n\n<section id=\"doc-feinterview\">\n<div class=\"ch-head\"><span class=\"ch-code\">PART</span><h2>프론트엔드 면접</h2></div>\n</section>\n\n<section id=\"feinterview-q0\" class=\"answer-card\" data-answer-model=\"definition mechanism cause effect tradeoff failure evidence defense\">\n<div class=\"ch-head\"><span class=\"ch-code\">FE-00</span><h2>프론트엔드 답변 원칙</h2></div>\n<p class=\"lede\">프론트엔드 답변은 기술명을 많이 말하는 것이 아니라 사용자 행동 하나가 React, 브라우저, 네트워크, 보안 경계를 지나며 어떤 비용과 실패를 만드는지 설명해야 합니다.</p>\n<div class=\"serial-card\"><span class=\"sc-label\">SPOKEN ANSWER MODEL</span>정의 → 내부 동작 → 원인 → 결과 → trade-off → 실패 모드 → 검증 증거 순서로 답합니다. 답변이 “useMemo를 씁니다”에서 끝나면 구현 방법만 말한 것이고, “어떤 state 변경이 어떤 render와 layout 비용을 만들었고 어떤 수치로 줄었는가”까지 말해야 면접 답변이 됩니다.</div>\n<h3>답변 밀도 기준</h3>\n<p>각 답변은 먼저 개념의 경계를 잡고, 그 다음 내부 동작을 설명하며, 마지막에 실패했을 때 사용자가 겪는 결과와 검증 증거를 붙입니다. 예를 들어 렌더링 최적화는 memoization 이름보다 state update, render scheduling, reconciliation, commit, browser layout/paint 중 어느 단계가 병목인지 분리해야 합니다.</p>\n<h3>약한 답변을 바꾸는 방식</h3>\n<table>\n<tr><th>약한 답변</th><th>강한 답변으로 바꾸는 기준</th></tr>\n<tr><td>React.memo를 사용합니다.</td><td>왜 다시 렌더링됐는지, props 참조가 왜 바뀌었는지, memo가 왜 효과가 없었는지, commit duration이 어떻게 바뀌었는지 말합니다.</td></tr>\n<tr><td>성능을 최적화했습니다.</td><td>LCP, INP, CLS 중 어떤 지표가 나빴고, TTFB, render-blocking resource, long task, layout box 중 어느 원인을 줄였는지 말합니다.</td></tr>\n<tr><td>보안을 신경 씁니다.</td><td>untrusted source가 어떤 sink로 들어가는지, XSS/CSRF/cache 노출이 어떤 결과로 이어지는지, CSP나 Trusted Types가 어떤 한계를 갖는지 말합니다.</td></tr>\n</table>\n</section>\n\n<section id=\"feinterview-q1\">\n<div class=\"ch-head\"><span class=\"ch-code\">FE-01</span><h2>Q. 브라우저 렌더링 파이프라인을 설명해보세요.</h2></div>\n<h3>핵심 개념</h3>\n<p>브라우저는 HTML을 DOM으로, CSS를 CSSOM으로 파싱한 뒤 Render Tree를 만들고 Layout, Paint, Composite 순서로 화면을 그립니다. 면접에서 중요한 지점은 순서 암기가 아니라 어떤 변경이 layout까지 영향을 주고, 어떤 변경은 composite에서 끝나는지 구분하는 것입니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>DOM은 문서 구조, CSSOM은 스타일 규칙, Render Tree는 실제로 그려질 노드의 조합입니다. <code>display:none</code> 요소는 Render Tree에서 빠지지만 <code>visibility:hidden</code>은 공간을 차지합니다. Layout은 각 박스의 크기와 위치를 계산하는 단계라 부모·자식·형제 관계의 영향을 크게 받고, Paint는 계산된 박스를 픽셀로 채우며, Composite는 여러 layer를 GPU가 합성하는 단계입니다. 그래서 “DOM 변경이 있었다”가 아니라 “이 변경이 어떤 단계까지 무효화하는가”가 성능 사고의 핵심입니다.</p>\n</div>\n<h3>30초 답변</h3>\n<div class=\"serial-card\">브라우저는 DOM과 CSSOM을 만들고 Render Tree를 구성한 뒤 Layout, Paint, Composite 단계로 화면을 그립니다. 실무에서는 `width`, `top`처럼 layout을 다시 계산하게 만드는 변경과, 조건이 맞으면 compositor 계층에서 처리될 수 있는 `transform`, `opacity` 변경을 구분하는 것이 성능 최적화의 핵심입니다.</div>\n<h3>원인-결과 흐름</h3>\n<p>DOM을 쓴 직후 layout 값을 읽으면 브라우저가 최신 위치와 크기를 보장하려고 forced synchronous layout을 수행할 수 있습니다. 이런 읽기/쓰기가 반복되면 layout thrashing이 되고, 큰 subtree의 layout과 paint가 반복되어 입력과 animation frame을 밀어냅니다. layout containment는 영향 범위를 줄이고, transform/opacity는 조건이 맞으면 compositor layer에서 처리되어 layout을 피할 수 있습니다. 다만 layer promotion과 <code>will-change</code>는 GPU memory를 쓰므로 오래 남기면 memory pressure와 paint 비용을 키울 수 있습니다.</p>\n<h3>90초 발화형 답변</h3>\n<p>브라우저 렌더링은 순서 암기보다 어떤 코드가 어느 단계를 무효화하는지 설명하는 것이 중요합니다. 예를 들어 DOM style을 바꾼 뒤 바로 <code>getBoundingClientRect</code>를 읽으면 브라우저가 forced synchronous layout을 수행할 수 있고, 이 패턴이 반복되면 layout thrashing으로 frame budget을 넘깁니다. 반대로 transform이나 opacity는 조건이 맞으면 composite 단계에서 처리될 수 있어 animation에 유리합니다. 하지만 layer promotion은 GPU memory를 사용하므로 <code>will-change</code>를 남용하면 오히려 메모리와 paint 비용이 늘 수 있습니다. 그래서 저는 Performance 탭에서 style recalculation, layout, paint, composite 비용을 분리해 보고, containment나 batched DOM read/write로 영향 범위를 줄입니다.</p>\n<h3>실패 모드</h3>\n<p>모든 animation을 compositor로 보내려고 layer를 과하게 만들면 GPU memory가 늘고 low-end device에서 frame drop이 생길 수 있습니다. 반대로 layout 값을 반복해서 읽는 코드를 방치하면 작은 UI 변경도 전체 layout 비용으로 번집니다.</p>\n<h3>검증 증거</h3>\n<p>Chrome Performance 탭의 forced reflow 경고, style recalculation/layout/paint/composite 비용, layer count, frame drop, layout containment 적용 전후를 증거로 제시합니다.</p>\n<h3>압박 질문 방어</h3>\n<p>“transform이면 항상 빠른가요?”에는 layout을 피할 가능성이 높지만 layer promotion과 GPU memory 비용이 있어 측정이 필요하다고 답합니다. “will-change를 미리 넣으면 좋지 않나요?”에는 짧은 구간에만 쓰고 오래 남기지 않는다고 답합니다.</p>\n<h3>면접에서 말할 증거</h3>\n<p>Chrome Performance 탭에서 layout/paint/composite 비용을 비교한 캡처, 애니메이션 변경 전후 frame drop, layout thrashing 재현 코드와 수정 결과를 말하면 신뢰도가 올라갑니다.</p>\n<h3>꼬리질문</h3>\n<table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>layout thrashing이 뭔가요?</td><td>DOM 읽기와 쓰기가 번갈아 일어나 브라우저가 강제로 layout을 반복 계산하는 문제입니다.</td></tr><tr><td>reflow와 repaint 차이는?</td><td>reflow는 위치와 크기 재계산, repaint는 픽셀 다시 그리기입니다. reflow가 보통 더 비쌉니다.</td></tr><tr><td>React 성능과 어떤 관련이 있나요?</td><td>React 렌더링 이후 실제 DOM 변경이 브라우저 렌더링 비용으로 이어지므로 둘을 함께 봐야 합니다.</td></tr></table>\n<h3>오답/주의점</h3>\n<div class=\"callout warn\"><span class=\"co-label\">주의</span><p>“React가 virtual DOM이라 빠릅니다”로 끝내면 약합니다. React 최적화와 브라우저 렌더링 비용은 다른 계층입니다.</p></div>\n</section>\n\n<section id=\"feinterview-q2\">\n<div class=\"ch-head\"><span class=\"ch-code\">FE-02</span><h2>Q. React 렌더링 최적화는 어떻게 하나요?</h2></div>\n<h3>핵심 개념</h3>\n<p>React 최적화는 memo를 붙이는 작업이 아니라 렌더링 원인, state 위치, props 참조 안정성, 리스트 key, 비싼 계산, 브라우저 렌더링 비용을 함께 보는 과정입니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>React에서 state update는 즉시 DOM을 바꾸는 명령이 아니라 다음 UI tree를 계산하도록 작업을 예약하는 신호입니다. render phase에서는 컴포넌트 함수가 실행되고 element tree가 만들어지며, reconciliation은 이전 tree와 다음 tree를 비교해 어떤 fiber를 유지할지 결정합니다. key가 안정적이면 state preservation이 가능하지만 key가 바뀌면 같은 위치의 UI라도 state가 초기화될 수 있습니다. commit phase에서는 실제 DOM mutation과 ref/effect 연결이 일어나고, 그 뒤 브라우저의 style calculation, layout/paint가 사용자 지연으로 보입니다.</p>\n</div>\n<h3>30초 답변</h3>\n<div class=\"serial-card\">저는 먼저 느린 지점이 React render 비용인지, commit DOM mutation 비용인지, 이후 browser layout/paint 비용인지 나눕니다. 같은 “렌더링이 느리다”라도 원인이 parent state 범위, props 참조 변경, key 불안정, context 전파, layout thrashing 중 어디냐에 따라 해결책이 달라집니다.</div>\n<h3>원인-결과 흐름</h3>\n<p>state update가 발생하면 render scheduling이 일어나고, 부모 컴포넌트가 다시 실행되면서 새 object/function props가 만들어질 수 있습니다. 이 참조가 child로 내려가면 <code>memo</code>가 있어도 props equality가 깨지고, reconciliation 범위가 넓어지며, commit에서 DOM mutation이 커지거나 commit 이후 layout/paint 비용이 커집니다. Strict Mode에서는 개발 중 render/effect가 반복되어 cleanup 누락과 idempotency 문제도 더 잘 드러납니다.</p>\n<h3>90초 발화형 답변</h3>\n<p>React 렌더링 최적화는 memo를 먼저 붙이는 일이 아니라 원인을 분리하는 일이라고 봅니다. 예를 들어 입력이 느린 화면이면 React Profiler로 어떤 컴포넌트가 왜 다시 렌더링되는지 확인하고, Chrome Performance에서 commit 이후 layout/paint나 long task가 있는지도 같이 봅니다. 상위 state가 너무 넓어 child가 계속 재실행된다면 state를 더 가까운 곳으로 내리고, 매 렌더마다 새 object/function을 props로 넘긴다면 데이터 구조와 callback 경계를 안정화합니다. key가 불안정해서 state preservation이 깨지는 경우도 있어서 list key와 remount 여부를 확인합니다. 그 다음 실제 비용이 큰 컴포넌트에만 memoization을 적용하고, 대용량 리스트라면 virtualization이나 pagination으로 렌더링 대상 자체를 줄입니다.</p>\n<h3>실패 모드</h3>\n<p><code>React.memo</code>를 넓게 붙였는데 props 참조가 계속 바뀌면 비교 비용만 늘고 효과는 없습니다. 반대로 render phase는 가벼운데 DOM이 크게 바뀌거나 layout이 반복되는 문제라면 memoization보다 DOM 구조, style 변경, virtualization이 더 중요합니다.</p>\n<h3>검증 증거</h3>\n<p>React Profiler의 render reason, commit duration, why-did-you-render 로그, Chrome Performance의 layout/paint 비용, 입력 지연 p95, 스크롤 FPS를 전후로 비교합니다.</p>\n<h3>압박 질문 방어</h3>\n<p>“memo를 붙였는데 왜 안 빨라졌나요?”라는 질문에는 props 참조가 불안정하거나 실제 병목이 render가 아니라 layout/paint일 수 있다고 답합니다. “useCallback을 많이 쓰면 좋은가요?”에는 참조 안정성이 필요한 경계에서만 쓰고, dependency 관리와 코드 복잡도 비용을 같이 본다고 답합니다.</p>\n<h3>꼬리질문</h3>\n<table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>useMemo를 많이 쓰면 좋은가요?</td><td>아닙니다. 계산 비용과 참조 안정성이 실제 병목일 때만 의미가 있고, 자체 관리 비용도 있습니다.</td></tr><tr><td>Context가 느린 이유는?</td><td>provider value가 바뀌면 consumer가 넓게 다시 렌더링될 수 있어서 값 분리와 selector 패턴이 필요합니다.</td></tr><tr><td>key는 왜 중요한가요?</td><td>React가 기존 element와 새 element를 매칭하는 기준이라 불안정하면 상태 보존과 렌더링 비용이 깨집니다.</td></tr></table>\n<h3>오답/주의점</h3>\n<div class=\"callout warn\"><span class=\"co-label\">주의</span><p>최적화 경험을 말할 때 “memo를 썼습니다”보다 “Profiler에서 병목을 확인했고, 어떤 렌더링 원인을 줄였습니다”라고 말해야 합니다.</p></div>\n<h3>면접에서 말할 증거</h3>\n<p>React DevTools Profiler의 commit duration, why-did-you-render 로그, 렌더링 횟수 변화, virtualization 적용 전후 스크롤 FPS를 준비합니다.</p>\n</section>\n\n<section id=\"feinterview-q3\">\n<div class=\"ch-head\"><span class=\"ch-code\">FE-03</span><h2>Q. 상태관리는 어떻게 설계하나요?</h2></div>\n<h3>핵심 개념</h3>\n<p>상태관리는 라이브러리 선택보다 경계 설정 문제입니다. 서버 상태, 클라이언트 UI 상태, form draft, URL state, 전역 app state를 섞으면 저장 취소, dirty check, validation, cache invalidation이 어려워집니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>상태는 “값을 어디에 저장할까”가 아니라 “누가 진실의 원천인가”의 문제입니다. 서버 상태의 진실은 서버에 있고 프론트의 값은 캐시입니다. form draft의 진실은 사용자가 아직 저장하지 않은 입력이고, URL state의 진실은 공유 가능한 주소입니다. 이 경계를 섞으면 사용자가 취소를 눌렀을 때 돌아갈 원본이 없어지고, refetch가 들어왔을 때 편집 중인 값이 덮이며, 서버 validation 실패를 어느 상태에 반영해야 하는지 모호해집니다.</p>\n</div>\n<h3>30초 답변</h3>\n<div class=\"serial-card\">저는 상태를 저장 위치가 아니라 책임으로 나눕니다. 서버에서 온 값은 server snapshot이고, 사용자가 아직 저장하지 않은 값은 draft이며, dirty와 validation error는 복구와 저장 판단을 위한 별도 상태입니다.</div>\n<h3>원인-결과 흐름</h3>\n<p>server snapshot과 draft를 같은 객체로 다루면 refetch가 들어왔을 때 편집 중인 값이 덮이거나, 저장 실패 후 원래 값으로 rollback할 기준이 사라집니다. dirty field와 validation error를 분리하지 않으면 어떤 row가 변경됐고 어떤 오류가 서버 검증에서 온 것인지 모호해집니다. 그래서 복잡한 입력 UI는 server snapshot, draft, dirty, validation error, submit status, rollback 기준을 분리해야 합니다.</p>\n<h3>90초 발화형 답변</h3>\n<p>상태관리는 먼저 진실의 원천을 나누는 문제라고 봅니다. 서버에서 받은 데이터는 프론트가 소유한 원본이 아니라 특정 시점의 server snapshot이고, 사용자가 입력 중인 값은 아직 저장되지 않은 draft입니다. 이 둘을 섞으면 취소, 저장 실패, 동시 수정, refetch 상황에서 복구가 어려워집니다. 그래서 form이나 grid에서는 draft, dirty field, validation error를 별도로 두고, 서버 상태는 query cache와 invalidation 정책으로 관리합니다. optimistic update를 쓰는 경우에도 실패했을 때 어떤 snapshot으로 rollback할지와 사용자에게 어떤 오류 단위를 보여줄지 같이 설계합니다.</p>\n<h3>실패 모드</h3>\n<p>API 응답을 전역 store에 복사하고 그 값을 그대로 편집하면 query cache와 store가 서로 다른 원본이 됩니다. 이 상태에서 refetch, 저장 실패, 동시 수정이 겹치면 화면은 성공처럼 보이지만 서버에는 반영되지 않은 값이 남거나, 사용자가 고친 draft가 조용히 사라질 수 있습니다.</p>\n<h3>검증 증거</h3>\n<p>상태 구조도, 저장 실패 rollback 화면, 서버 validation error 매핑, stale/refetch 정책, optimistic update 실패 테스트를 증거로 제시합니다.</p>\n<h3>압박 질문 방어</h3>\n<p>“그냥 Redux에 다 넣으면 편하지 않나요?”라는 질문에는 전역 store가 편의는 줄 수 있지만 서버 상태의 최신성, invalidation, retry, dedupe 책임까지 직접 떠안게 된다고 답합니다. “상태 라이브러리 기준은요?”에는 공유 범위, 쓰기 빈도, 디버깅 필요성, 실패 복구 기준으로 고른다고 답합니다.</p>\n<h3>꼬리질문</h3>\n<table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>Redux와 Context 기준은?</td><td>Context는 read-heavy 전역 값에 적합하고, 복잡한 write, 디버깅, 확장 처리가 필요하면 store를 봅니다.</td></tr><tr><td>URL state는 언제 쓰나요?</td><td>검색, 필터, 정렬, 페이지처럼 공유/복원 가능한 상태에 씁니다.</td></tr><tr><td>서버 상태 도구가 필요한 이유는?</td><td>캐시, refetch, stale time, dedupe, retry 같은 서버 동기화 문제를 직접 구현하지 않기 위해서입니다.</td></tr></table>\n<h3>오답/주의점</h3>\n<div class=\"callout warn\"><span class=\"co-label\">주의</span><p>“전역으로 두면 편합니다”는 약한 답입니다. 전역 상태는 편의가 아니라 공유 범위와 변경 비용을 근거로 정해야 합니다.</p></div>\n<h3>면접에서 말할 증거</h3>\n<p>서버 원본, 편집 draft, dirty flag, validation error를 분리한 상태 구조도와 저장 실패 복구 흐름을 예로 들면 좋습니다.</p>\n</section>\n\n<section id=\"feinterview-q4\">\n<div class=\"ch-head\"><span class=\"ch-code\">FE-04</span><h2>Q. CSR, SSR, SSG, ISR은 어떻게 선택하나요?</h2></div>\n<h3>핵심 개념</h3>\n<p>렌더링 전략은 페이지 성격, SEO, 초기 표시, 개인화, 데이터 변경 빈도, 서버 비용, hydration 비용으로 판단합니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>CSR은 브라우저가 JavaScript를 받은 뒤 화면을 만들기 때문에 서버 부담은 낮지만 첫 화면과 검색 엔진 대응이 약할 수 있습니다. SSR은 서버가 HTML을 먼저 만들어 보내므로 초기 표시와 크롤링에는 유리하지만, 서버에서 만든 HTML에 클라이언트 이벤트를 연결하는 hydration 비용이 뒤따릅니다. SSG는 빌드 시점 HTML을 만들고, ISR은 정적 결과를 캐시하면서 일정 조건에서 갱신합니다. 즉 선택 기준은 “어디서 렌더링하는가”보다 “언제 데이터가 확정되고, 누구에게 같은 화면을 보여줄 수 있는가”입니다.</p>\n</div>\n<h3>30초 답변</h3>\n<div class=\"serial-card\">SEO와 초기 로딩이 중요한 공개 페이지는 SSR이나 SSG가 유리하고, 로그인 이후 개인화와 상호작용이 강한 화면은 CSR이 자연스러운 경우가 많습니다. ISR은 정적 페이지를 캐시하되 stale 시간이 지난 뒤 요청 흐름에서 재검증하거나 재생성하는 절충안입니다.</div>\n<h3>원인-결과 흐름</h3>\n<p>공개 상품 페이지는 검색 노출과 첫 HTML이 중요하므로 SSG나 ISR이 유리하지만 가격·재고 freshness가 중요하면 재검증 정책이 필요합니다. 로그인 대시보드는 사용자별 권한과 개인화 데이터가 많아 public cache를 쓰기 어렵고, SSR을 쓰더라도 cache key와 session 경계를 신중히 잡아야 합니다. 개인화 검색 결과는 query, 권한, 정렬 조건이 매번 달라 CSR 또는 서버 데이터 fetch와 client boundary 조합이 자연스러울 수 있습니다. streaming SSR은 Suspense boundary 단위로 먼저 준비된 HTML을 보낼 수 있지만, RSC client boundary를 잘못 잡으면 bundle 절감보다 hydration waterfall과 상태 경계 혼선이 커질 수 있습니다.</p>\n<h3>90초 발화형 답변</h3>\n<p>렌더링 전략은 프레임워크 기능명을 고르는 문제가 아니라 페이지의 데이터 확정 시점과 사용자별 차이를 보는 문제입니다. 공개 상품 페이지처럼 SEO와 cache 효율이 중요하고 사용자별 차이가 작으면 SSG나 ISR을 먼저 봅니다. 로그인 대시보드처럼 권한별 데이터가 섞이면 SSR을 쓰더라도 cache가 개인화 응답을 공유하지 않도록 private 정책과 session 경계를 확인합니다. 개인화 검색 결과는 쿼리와 필터가 자주 바뀌기 때문에 CSR이나 서버 상태 도구가 더 단순할 수 있습니다. streaming SSR은 초기 표시를 앞당길 수 있지만 Suspense boundary가 너무 크면 중요한 정보가 fallback 뒤에 숨고, RSC client boundary가 많아지면 결국 client bundle과 hydration 비용이 다시 커질 수 있습니다.</p>\n<h3>실패 모드</h3>\n<p>공개 페이지에 CSR만 쓰면 크롤링과 초기 표시가 약해질 수 있고, 개인화 페이지에 aggressive cache를 쓰면 다른 사용자의 데이터가 노출될 수 있습니다. SSR을 무조건 선택하면 서버 비용, TTFB, hydration mismatch, cache invalidation 문제가 커집니다.</p>\n<h3>검증 증거</h3>\n<p>페이지 유형별 TTFB, HTML cache hit, hydration duration, LCP, bundle size, RSC client boundary 수, 개인화 cache header 점검 결과를 증거로 제시합니다.</p>\n<h3>압박 질문 방어</h3>\n<p>“Next.js면 SSR이 정답 아닌가요?”에는 공개 상품 페이지, 로그인 대시보드, 개인화 검색 결과가 서로 다른 제약을 가진다고 답합니다. “streaming SSR이면 다 빨라지나요?”에는 boundary 설계와 hydration waterfall을 함께 봐야 한다고 답합니다.</p>\n<h3>꼬리질문</h3>\n<table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>hydration mismatch는 왜 생기나요?</td><td>서버 HTML과 클라이언트 첫 렌더 결과가 다를 때 생기며 시간, 랜덤값, 브라우저 전용 상태가 흔한 원인입니다.</td></tr><tr><td>SSR이 항상 좋은가요?</td><td>아닙니다. 서버 비용과 hydration 비용이 생기므로 페이지 목적에 맞춰야 합니다.</td></tr><tr><td>RSC는 왜 어렵나요?</td><td>서버 데이터, 클라이언트 이벤트, 로컬 상태 경계를 명확히 나누지 않으면 디버깅이 어려워집니다.</td></tr></table>\n<h3>오답/주의점</h3>\n<div class=\"callout warn\"><span class=\"co-label\">주의</span><p>Next.js 기능명을 나열하기보다 페이지별 요구사항과 비용을 기준으로 선택한다고 말해야 합니다.</p></div>\n<h3>면접에서 말할 증거</h3>\n<p>Lighthouse 지표, TTFB와 hydration 비용, SEO 요구, 캐시 헤더, 페이지별 개인화 여부를 비교한 의사결정 표를 말합니다.</p>\n</section>\n\n<section id=\"feinterview-q5\">\n<div class=\"ch-head\"><span class=\"ch-code\">FE-05</span><h2>Q. 웹 성능을 어떻게 측정하고 개선하나요?</h2></div>\n<h3>핵심 개념</h3>\n<p>성능은 번들 크기, 네트워크, 이미지, 렌더링, JavaScript long task, API 응답 구조가 함께 만드는 사용자 체감입니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>성능 지표는 서로 다른 병목을 가리킵니다. LCP는 주요 콘텐츠가 언제 보이는지, CLS는 화면이 얼마나 흔들리는지, INP는 사용자의 입력에 얼마나 빨리 반응하는지를 봅니다. 번들이 작아도 API가 느리면 LCP가 나빠질 수 있고, 이미지는 빨리 떠도 메인 스레드 long task가 길면 클릭 반응이 늦습니다. 그래서 성능 개선은 “빠르게 만들었다”가 아니라 network, main thread, rendering, server latency 중 어느 병목을 줄였는지 증명하는 작업입니다.</p>\n</div>\n<h3>30초 답변</h3>\n<div class=\"serial-card\">저는 성능을 LCP, INP, CLS 같은 사용자 체감 지표로 먼저 나누고, 각 지표를 네트워크, 메인 스레드, 렌더링, 서버 응답 중 어느 계층 문제인지 추적합니다. 개선 후에는 lab data뿐 아니라 field data의 p75나 p95도 같이 봅니다.</div>\n<h3>원인-결과 흐름</h3>\n<p>LCP가 느리면 TTFB가 길거나 render-blocking CSS/JS 때문에 LCP 후보 리소스 발견이 늦고, 이미지 다운로드와 디코딩이 밀리면서 주요 콘텐츠 표시가 지연됩니다. INP는 사용자의 입력 이후 event handler, 큰 JSON parsing, list filtering, synchronous validation 같은 long task가 main thread를 점유해 next paint를 늦출 때 악화됩니다. CLS는 이미지 크기 미지정, late font swap, 동적 배너 삽입처럼 layout box가 뒤늦게 바뀔 때 증가합니다.</p>\n<h3>90초 발화형 답변</h3>\n<p>웹 성능은 “빠르게 만들었다”가 아니라 어떤 지표의 어떤 병목을 줄였는지로 설명해야 한다고 봅니다. 초기 표시가 느리면 먼저 Network waterfall로 TTFB, render-blocking resource, LCP image priority를 확인하고, JavaScript 실행 비용이 크면 Performance 탭에서 parse/compile/execute와 long task를 봅니다. 상호작용이 느리면 React Profiler와 Performance를 함께 보고, event handler나 validation이 next paint를 막는지 확인합니다. CLS가 문제라면 이미지와 동적 영역의 layout box가 처음부터 예약되는지 봅니다. 수정 후에는 Lighthouse 한 번이 아니라 throttling 조건, Core Web Vitals field data, p75/p95 사용자 지표를 전후 비교합니다.</p>\n<h3>실패 모드</h3>\n<p>번들만 줄였는데 LCP 원인이 TTFB나 LCP 이미지 우선순위라면 체감 개선이 작습니다. preload를 과하게 넣으면 실제 LCP 후보가 아닌 자원이 네트워크를 선점해 더 느려질 수 있고, long task를 줄이지 않으면 INP는 그대로 나쁠 수 있습니다.</p>\n<h3>검증 증거</h3>\n<p>CrUX나 RUM의 field data, Lighthouse lab data, Network waterfall, Chrome Performance long task, LCP candidate 기록, INP event timing, CLS layout shift entry를 근거로 제시합니다.</p>\n<h3>압박 질문 방어</h3>\n<p>“Lighthouse 점수만 올리면 충분한가요?”에는 lab data는 재현과 비교에 좋지만 실제 사용자의 기기와 네트워크를 반영하는 field data도 봐야 한다고 답합니다. “이미지를 최적화했는데 왜 느린가요?”에는 서버 응답, render-blocking resource, hydration, main thread long task가 LCP/INP를 막을 수 있다고 답합니다.</p>\n<h3>꼬리질문</h3>\n<table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>LCP 개선은?</td><td>hero image, font, critical CSS, server response, render-blocking resource를 봅니다.</td></tr><tr><td>INP 개선은?</td><td>long task를 줄이고 비싼 계산을 분리하거나 debounce, worker, virtualization을 검토합니다.</td></tr><tr><td>수치가 없으면?</td><td>정량 지표가 없으면 재현 조건, 측정 도구, 체감 병목, QA 감소 같은 증거를 말합니다.</td></tr></table>\n<h3>오답/주의점</h3>\n<div class=\"callout warn\"><span class=\"co-label\">주의</span><p>“렌더링 최적화했습니다”보다 어떤 지표를 보고 어떤 병목을 줄였는지 말해야 합니다.</p></div>\n<h3>면접에서 말할 증거</h3>\n<p>Core Web Vitals, bundle analyzer, Network waterfall, long task 캡처, 이미지 최적화 전후 LCP 변화 같은 수치를 준비합니다.</p>\n</section>\n\n<section id=\"feinterview-q6\">\n<div class=\"ch-head\"><span class=\"ch-code\">FE-06</span><h2>Q. 접근성은 실무에서 어떻게 챙기나요?</h2></div>\n<h3>핵심 개념</h3>\n<p>접근성은 나중에 붙이는 장식이 아니라 semantic HTML, 키보드 탐색, focus management, 명도 대비, 상태 전달을 포함한 컴포넌트 품질 기준입니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>브라우저는 DOM을 그대로 보조기술에 전달하지 않고 접근성 트리(accessibility tree)로 변환합니다. <code>button</code>과 <code>a</code> 같은 대화형 요소는 role, accessible name 계산, focus, 키보드 활성화 동작을 기본으로 제공하고, <code>label</code>과 heading 같은 의미 요소는 입력 이름 연결과 문서 구조를 보조기술에 전달합니다. 반대로 <code>div</code>에 클릭 이벤트만 붙이면 마우스로는 동작해도 키보드 사용자와 스크린 리더 사용자에게는 버튼으로 인식되지 않습니다. 접근성은 ARIA 속성 암기가 아니라 브라우저가 이미 제공하는 의미와 상호작용을 깨지 않는 설계입니다.</p>\n</div>\n<h3>30초 답변</h3>\n<div class=\"serial-card\">기본은 semantic HTML, 키보드 접근, focus 표시와 이동, 명도 대비, 상태 변화 전달입니다. ARIA는 기본 HTML 구조를 대체하는 것이 아니라 보완하는 수단으로 봅니다.</div>\n<h3>원인-결과 흐름</h3>\n<p>대화형 요소가 semantic HTML을 잃으면 브라우저가 role, keyboard activation, accessible name을 자동으로 제공하지 못합니다. 그래서 <code>div</code> 버튼은 click은 되지만 keyboard와 screen reader에서는 버튼으로 인식되지 않을 수 있습니다. modal은 focus trap, focus return, Escape 처리, labeling이 없으면 사용자가 배경으로 빠지거나 현재 대화상자의 이름을 알 수 없습니다. 상태 변경은 <code>aria-live</code> 같은 announcement 경로가 없으면 보조기술 사용자에게 전달되지 않고, composite widget은 roving tabindex 없이 모든 item을 tab stop으로 만들면 탐색 비용이 폭증합니다. virtualized list/grid는 DOM에 없는 row를 보조기술이 알 수 없으므로 row count, focus 유지, 대체 탐색을 설계해야 합니다.</p>\n<h3>90초 발화형 답변</h3>\n<p>접근성은 ARIA를 많이 붙이는 일이 아니라 브라우저가 제공하는 의미와 상호작용을 깨지 않는 일이라고 봅니다. 먼저 button, a, label, heading 같은 semantic HTML을 사용해 role과 accessible name을 자연스럽게 만들고, 부족한 정보만 ARIA로 보완합니다. modal은 focus trap, Escape, aria-labelledby, 닫힌 뒤 focus return을 확인하고, toast나 비동기 저장 결과는 aria-live로 전달해야 합니다. 복합 위젯은 roving tabindex로 keyboard 탐색 범위를 제어하고, disabled와 aria-disabled는 실제 focus 가능성과 submit 가능성 차이를 이해하고 선택합니다. virtualized list/grid는 보이는 DOM만 존재하기 때문에 screen reader와 keyboard focus가 끊기지 않는지 별도 검증이 필요합니다.</p>\n<h3>실패 모드</h3>\n<p>ARIA로 native semantics를 흉내 내다 role과 keyboard 동작이 어긋나면 화면상으로는 정상이어도 keyboard 사용자에게는 사용할 수 없는 컴포넌트가 됩니다. <code>aria-disabled</code>를 쓰고 실제 click handler를 막지 않으면 비활성처럼 보이는 버튼이 실행될 수도 있습니다.</p>\n<h3>검증 증거</h3>\n<p>keyboard-only 탐색 녹화, accessible name 점검, screen reader smoke test, axe/Lighthouse 결과, focus trap 테스트, aria-live announcement 확인, virtualized grid focus 유지 테스트를 증거로 제시합니다.</p>\n<h3>압박 질문 방어</h3>\n<p>“ARIA를 붙이면 접근성이 좋아지나요?”에는 native semantic을 먼저 쓰고 ARIA는 보완 수단이라고 답합니다. “Lighthouse 점수만 보면 되나요?”에는 자동 도구는 일부만 잡으므로 keyboard와 screen reader 수동 흐름을 같이 본다고 답합니다.</p>\n<h3>꼬리질문</h3>\n<table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>ARIA를 많이 쓰면 좋은가요?</td><td>아닙니다. native semantic을 먼저 쓰고 부족한 정보만 보완합니다.</td></tr><tr><td>모달 접근성은?</td><td>role/dialog, label, focus trap, Escape, 배경 inert 처리, 닫은 뒤 focus 복귀를 봅니다.</td></tr><tr><td>검증은 어떻게 하나요?</td><td>키보드만 사용, screen reader smoke test, axe/Lighthouse, 수동 focus flow를 봅니다.</td></tr></table>\n<h3>오답/주의점</h3>\n<div class=\"callout warn\"><span class=\"co-label\">주의</span><p>접근성을 “시간 나면 하는 것”으로 말하면 약합니다. 기본 구조는 처음부터 넣어야 합니다.</p></div>\n<h3>면접에서 말할 증거</h3>\n<p>키보드 탐색 녹화, axe/Lighthouse 결과, focus trap 테스트, 스크린 리더 smoke test 체크리스트를 예로 듭니다.</p>\n</section>\n\n<section id=\"feinterview-q7\">\n<div class=\"ch-head\"><span class=\"ch-code\">FE-07</span><h2>Q. 프론트엔드 보안은 어떻게 보나요?</h2></div>\n<h3>핵심 개념</h3>\n<p>프론트엔드 보안은 XSS, CSRF, token storage, CORS, 민감정보 노출, 권한 우회를 클라이언트와 서버 경계로 나눠 보는 것입니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>프론트엔드는 사용자의 브라우저에서 실행되므로 클라이언트 상태와 UI 조건은 신뢰 경계 밖에 있다고 봐야 합니다. 공격자는 API를 직접 호출하거나 요청 값을 바꿀 수 있고, XSS가 생기면 우리 origin의 JavaScript 실행 환경과 브라우저 저장소에 접근할 수 있습니다. 그래서 “화면에서 버튼을 숨긴다”는 권한 방어가 아니라 UX 처리입니다. XSS는 token storage, 사용자 대신 요청, 화면 변조로 이어질 수 있고, CORS는 다른 origin의 브라우저 요청을 제한하는 정책이지 서버 API의 인증·인가를 대신하지 않습니다.</p>\n</div>\n<h3>30초 답변</h3>\n<div class=\"serial-card\">프론트엔드 보안은 source에서 들어온 untrusted data가 어떤 sink로 흘러가는지 추적하는 일입니다. UI 권한 체크는 UX이고, 최종 인가는 서버가 해야 하지만 프론트도 XSS, cache 노출, token 저장, 민감정보 로그 같은 공격면을 줄여야 합니다.</div>\n<h3>원인-결과 흐름</h3>\n<p>사용자 입력, 외부 API, CMS, markdown 파일 같은 source가 markdown/html/SVG/URL 변환을 거쳐 <code>innerHTML</code>, script URL, redirect URL, DOM attribute 같은 sink로 들어가면 XSS나 open redirect가 됩니다. XSS가 발생하면 localStorage token 탈취, 사용자 대신 요청, 화면 변조로 이어질 수 있습니다. Trusted Types는 dangerous sink에 문자열이 직접 들어가는 것을 막고, CSP nonce/hash는 허용된 script 실행을 좁히지만 sanitizer bypass와 URL allowlist 오류는 별도로 점검해야 합니다.</p>\n<p>source와 sink를 먼저 식별한 뒤 markdown renderer, SVG 허용 정책, URL protocol allowlist, Trusted Types 적용 범위, sanitizer bypass negative test를 같은 흐름에서 확인해야 합니다.</p>\n<h3>90초 발화형 답변</h3>\n<p>저는 프론트엔드 보안을 source-sink 흐름으로 설명합니다. 예를 들어 사용자가 입력한 markdown을 HTML로 렌더링한다면 입력 source, sanitizer, 허용 tag와 URL protocol, 최종 DOM sink를 나눠 봅니다. sanitizer가 있어도 SVG, DOM clobbering, mutation XSS, javascript URL 같은 sanitizer bypass가 가능하므로 CSP와 Trusted Types를 함께 고려합니다. token 저장도 XSS와 CSRF 중 어떤 위험을 더 크게 볼지의 trade-off입니다. localStorage는 구현이 쉽지만 XSS 때 token이 직접 탈취될 수 있고, httpOnly cookie는 JS 접근을 막지만 SameSite, CSRF token, Origin 검증이 필요합니다. 개인화 API 응답을 public cache에 넣으면 보안 사고가 되므로 Cache-Control과 Vary도 보안 경계로 봅니다.</p>\n<h3>실패 모드</h3>\n<p>프론트에서 버튼을 숨겼다고 권한이 막힌 것은 아닙니다. 공격자는 API를 직접 호출할 수 있습니다. 또 CSP만 켰다고 XSS가 사라지는 것도 아닙니다. markdown renderer나 sanitizer 설정이 틀리면 허용된 경로 안에서 우회될 수 있습니다.</p>\n<h3>검증 증거</h3>\n<p>source-sink 점검표, sanitizer negative test, CSP violation report, Trusted Types rollout 결과, token storage ADR, 서버 인가 실패 테스트, cache header 점검 결과를 증거로 제시합니다.</p>\n<h3>압박 질문 방어</h3>\n<p>“보안은 서버가 하는 것 아닌가요?”라는 질문에는 최종 인가는 서버 책임이지만 프론트는 DOM sink, token exposure, cache policy, 민감정보 로그 노출을 줄이는 책임이 있다고 답합니다. “CORS를 열면 안전한가요?”에는 CORS는 브라우저의 cross-origin 읽기 정책이지 인증과 인가를 대신하지 않는다고 답합니다.</p>\n<h3>꼬리질문</h3>\n<table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>localStorage token은 왜 위험한가요?</td><td>XSS가 발생하면 token 탈취가 쉬워집니다. httpOnly cookie와 trade-off를 비교해야 합니다.</td></tr><tr><td>CORS를 열면 안전한가요?</td><td>아닙니다. CORS는 브라우저 정책이고 서버 권한 검증은 별도로 필요합니다.</td></tr><tr><td>프론트 권한 체크로 충분한가요?</td><td>아닙니다. UI 숨김은 UX이고 서버가 최종 인가를 해야 합니다.</td></tr></table>\n<h3>오답/주의점</h3>\n<div class=\"callout warn\"><span class=\"co-label\">주의</span><p>“프론트에서는 보안이 불가능합니다”도 틀린 말입니다. 최종 방어선은 서버지만 프론트도 공격면을 줄여야 합니다.</p></div>\n<h3>면접에서 말할 증거</h3>\n<p>`innerHTML` 제거 사례, sanitizer 적용, CSP 리포트, token storage 결정 근거, 서버 인가 실패 케이스 테스트를 말합니다.</p>\n</section>\n\n<section id=\"feinterview-q8\">\n<div class=\"ch-head\"><span class=\"ch-code\">FE-08</span><h2>Q. 테스트 전략은 어떻게 가져가나요?</h2></div>\n<h3>핵심 개념</h3>\n<p>프론트엔드 테스트는 컴포넌트가 렌더되는지 확인하는 것이 아니라 사용자가 중요한 흐름을 완료할 수 있는지, 실패 상태에서 회복할 수 있는지 검증하는 것입니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>테스트 계층은 “더 실제에 가까울수록 좋다”가 아니라 결함을 가장 싸게 잡는 위치를 고르는 문제입니다. 순수 함수의 조건 분기는 unit test가 가장 빠르고 정확합니다. API 응답에 따라 화면이 바뀌는 흐름은 MSW 같은 네트워크 mock을 둔 integration test가 적합합니다. 브라우저 navigation, cookie, 실제 focus, file upload처럼 런타임 통합이 중요한 흐름은 E2E가 필요합니다. 좋은 테스트 전략은 같은 버그를 너무 비싼 계층에서 반복 검증하지 않는 것입니다.</p>\n</div>\n<h3>30초 답변</h3>\n<div class=\"serial-card\">순수 로직은 unit test, 컴포넌트 상호작용은 Testing Library, API와 연결된 흐름은 MSW 기반 integration test, 핵심 사용자 journey는 Playwright 같은 E2E로 검증합니다. 모든 것을 E2E로 하지 않고 위험도에 따라 나눕니다.</div>\n<h3>원인-결과 흐름</h3>\n<p>순수 함수의 분기 오류는 unit test가 가장 빠르게 잡지만, API 응답에 따른 화면 전환은 실제 network boundary를 흉내 내지 않으면 contract drift를 놓치기 쉽습니다. MSW 기반 integration test는 서버 응답 성공, 지연, 오류, validation error를 사용자 흐름 안에서 검증하게 해줍니다. Playwright E2E는 browser navigation, cookie, focus, file upload처럼 런타임 통합이 필요한 경로에 적합하지만, 너무 많이 두면 flaky test와 긴 feedback loop가 생깁니다.</p>\n<h3>90초 발화형 답변</h3>\n<p>프론트엔드 테스트는 모든 것을 E2E로 올리는 것이 아니라 버그를 가장 싸게 잡는 계층을 고르는 일입니다. formatter, validation rule, adapter처럼 입력과 출력이 명확한 코드는 unit test로 빠르게 잡습니다. API 응답에 따라 loading, empty, error, success 화면이 바뀌는 흐름은 MSW를 둔 integration test가 적합합니다. 로그인, 권한, 결제, 파일 업로드처럼 browser runtime과 backend 계약이 함께 깨질 수 있는 핵심 journey는 Playwright E2E로 최소 세트를 둡니다. 다만 E2E가 많아지면 flaky와 유지보수 비용이 커지므로 contract drift가 자주 나는 API는 schema나 mock fixture 관리까지 같이 봅니다.</p>\n<h3>실패 모드</h3>\n<p>mock이 실제 API와 달라지면 테스트는 통과하지만 운영에서 깨지는 contract drift가 생깁니다. 반대로 모든 테스트를 E2E로 만들면 느리고 flaky해져 팀이 테스트를 신뢰하지 않게 됩니다.</p>\n<h3>검증 증거</h3>\n<p>unit test의 validation 반례, MSW integration test의 error state, Playwright 핵심 journey, flaky test 격리 기록, API fixture 갱신 정책, 회귀 버그 재현 테스트를 증거로 제시합니다.</p>\n<h3>압박 질문 방어</h3>\n<p>“커버리지만 높으면 충분한가요?”에는 coverage보다 사용자가 실패하는 경로를 잡는지가 중요하다고 답합니다. “E2E가 제일 실제에 가까운데 다 E2E로 하면 되지 않나요?”에는 비용과 flaky 문제 때문에 위험도 높은 journey만 남긴다고 답합니다.</p>\n<h3>꼬리질문</h3>\n<table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>무엇부터 테스트하나요?</td><td>장애 비용이 큰 흐름, 반복 버그, 복잡한 validation과 adapter부터 잡습니다.</td></tr><tr><td>mock은 어디까지?</td><td>단위 테스트는 외부를 mock하고, 통합 테스트는 MSW로 API 계약에 가까운 응답을 둡니다.</td></tr><tr><td>E2E가 느리면?</td><td>핵심 happy path와 대표 error path만 남기고 나머지는 낮은 계층 테스트로 내립니다.</td></tr></table>\n<h3>오답/주의점</h3>\n<div class=\"callout warn\"><span class=\"co-label\">주의</span><p>“테스트 커버리지를 높였습니다”보다 어떤 사용자 위험을 줄였는지 말해야 합니다.</p></div>\n</section>\n\n<section id=\"feinterview-q9\">\n<div class=\"ch-head\"><span class=\"ch-code\">FE-09</span><h2>Q. 서버 상태와 클라이언트 UI 상태는 왜 분리하나요?</h2></div>\n<h3>핵심 개념</h3><p>서버 상태는 원격 원천 데이터의 캐시이고, UI 상태는 현재 화면의 표현과 상호작용 상태입니다. 둘을 섞으면 최신성, 저장 취소, optimistic update, 오류 복구가 어려워집니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>서버 상태에는 “내가 소유하지 않는 시간”이 있습니다. 다른 사용자가 바꿀 수 있고, 서버가 정렬·필터·권한에 따라 다른 결과를 줄 수 있으며, 네트워크 실패로 최신성이 흔들립니다. UI 상태는 현재 탭 안의 일시적 의도입니다. 선택된 행, 열린 모달, 입력 중인 값은 서버가 모르는 값입니다. 서버 상태 도구가 stale time, invalidation, deduplication을 다루는 이유는 이 원격 데이터의 시간 문제를 직접 구현하지 않기 위해서입니다.</p>\n</div>\n<h3>30초 답변</h3><div class=\"serial-card\">서버 상태는 stale time, refetch, retry, cache invalidation이 핵심이고 UI 상태는 모달, 선택 row, 입력 draft처럼 화면 근처에서 관리하는 것이 핵심입니다. 원천 데이터와 편집 중 데이터를 분리해야 취소, 저장 실패, 동시 수정에 대응할 수 있습니다.</div>\n<h3>90초 답변</h3><p>예를 들어 목록 API 결과를 그대로 수정 상태로 쓰면 저장 실패 시 원본으로 돌아가기 어렵고, 다른 사용자의 변경과 내 draft가 섞일 수 있습니다. 그래서 query cache는 서버 snapshot으로 두고, form/grid는 draft와 dirty field를 별도로 관리합니다. optimistic update는 사용자 체감에는 좋지만 rollback과 중복 요청 대응까지 설계해야 합니다.</p>\n<h3>꼬리질문</h3><table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>optimistic update는 언제?</td><td>실패 가능성이 낮고 rollback UX가 명확할 때 사용합니다.</td></tr><tr><td>stale time 기준은?</td><td>데이터 변경 빈도와 사용자가 허용할 수 있는 오래된 정도로 정합니다.</td></tr><tr><td>동시 수정은?</td><td>version, updatedAt, conflict UI, 서버 검증으로 다룹니다.</td></tr></table>\n<h3>면접에서 말할 증거</h3><p>query cache와 draft state 구조, 저장 실패 rollback 화면, stale/refetch 정책을 프로젝트 예시로 설명합니다.</p>\n<h3>오답/주의점</h3><div class=\"callout warn\"><span class=\"co-label\">주의</span><p>서버 데이터를 전역 store에 복사해 두는 방식은 캐시 중복과 최신성 문제를 만들 수 있습니다.</p></div>\n</section>\n\n<section id=\"feinterview-q10\">\n<div class=\"ch-head\"><span class=\"ch-code\">FE-10</span><h2>Q. hydration mismatch는 왜 생기고 어떻게 막나요?</h2></div>\n<h3>핵심 개념</h3><p>hydration mismatch는 서버가 만든 HTML과 클라이언트 첫 렌더 결과가 다를 때 생깁니다. 시간, 랜덤값, locale, 브라우저 전용 API, 인증 상태가 흔한 원인입니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>SSR에서 서버는 HTML 문자열을 만들고, 브라우저는 그 HTML을 먼저 보여준 뒤 React가 같은 컴포넌트 트리를 다시 계산해 이벤트를 연결합니다. 이때 React는 “이미 있는 DOM이 내가 계산한 첫 결과와 같다”고 가정합니다. 서버에는 <code>window</code>, viewport, localStorage, 사용자의 현재 시간대 같은 정보가 없으므로 클라이언트 첫 렌더에서 다른 값을 만들면 mismatch가 납니다. 핵심은 서버 렌더와 클라이언트 첫 렌더의 입력을 같게 만드는 것입니다.</p>\n</div>\n<h3>30초 답변</h3><div class=\"serial-card\">서버와 클라이언트의 첫 렌더 입력이 같아야 합니다. `Date.now`, random, window 접근, localStorage 기반 분기처럼 서버에서 알 수 없는 값은 client effect 이후로 미루거나 서버에서 동일한 값을 내려줘야 합니다.</div>\n<h3>원인-결과 흐름</h3>\n<p>SSR에서 서버는 HTML을 만들고 브라우저는 그 HTML을 먼저 보여준 뒤 React가 클라이언트에서 first render를 다시 계산해 이벤트를 연결합니다. 이때 <code>Date.now</code>, random, locale, viewport, <code>localStorage</code>, 인증 상태, feature flag처럼 서버와 클라이언트 입력이 다르면 기존 DOM과 첫 render 결과가 달라지고 hydration warning, 부분 재생성, 이벤트 연결 지연, 깜빡임이 생깁니다. 해결은 경고를 숨기는 것이 아니라 서버 initial data를 맞추거나 mounted 이후 분기, client-only boundary, Suspense boundary로 차이를 격리하는 것입니다.</p>\n<h3>90초 발화형 답변</h3><p>hydration mismatch는 서버 HTML과 클라이언트 첫 렌더 결과가 달라질 때 생깁니다. SSR의 목적은 HTML을 빨리 보내는 것에서 끝나지 않고, 클라이언트가 같은 입력으로 첫 render를 계산해 안정적으로 hydration을 끝내는 데 있습니다. 예를 들어 테마를 localStorage에서 바로 읽거나 <code>Date.now</code>로 시간을 렌더링하면 서버는 그 값을 알 수 없어 클라이언트 결과가 달라질 수 있습니다. 인증 UI도 서버 세션과 클라이언트 상태가 다르면 로그인/로그아웃 화면이 깜빡일 수 있습니다. 그래서 초기 렌더에 필요한 값은 cookie나 서버 initial props로 맞추고, 브라우저 전용 값은 mounted 이후 처리하거나 client-only boundary로 분리합니다. streaming SSR에서는 Suspense boundary를 너무 크게 잡으면 중요한 정보가 fallback 뒤에 숨고 hydration waterfall이 생길 수 있어 boundary 설계도 같이 봅니다.</p>\n<h3>실패 모드</h3>\n<p><code>suppressHydrationWarning</code>으로 경고만 숨기면 입력 불일치가 남아 이벤트 연결 지연, layout shift, 잘못된 초기 UI가 계속될 수 있습니다. 개인화 데이터를 public cache에 섞으면 mismatch를 넘어 다른 사용자 정보 노출로 이어질 수도 있습니다.</p>\n<h3>검증 증거</h3>\n<p>hydration warning 원인 diff, 서버 initial props 정리, mounted guard 적용 전후, localStorage 테마 처리 방식, streaming SSR waterfall, client-only boundary 적용 사례를 증거로 제시합니다.</p>\n<h3>압박 질문 방어</h3>\n<p>“경고만 숨기면 되지 않나요?”에는 경고를 숨기는 것과 서버/클라이언트 first render 입력을 맞추는 것은 다르다고 답합니다. “SSR이면 무조건 빠른가요?”에는 TTFB, hydration 비용, cache와 개인화 위험까지 비교해야 한다고 답합니다.</p>\n<h3>꼬리질문</h3><table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>suppressHydrationWarning은?</td><td>정말 불가피한 작은 차이에만 쓰고 근본 해결로 보지 않습니다.</td></tr><tr><td>localStorage 테마는?</td><td>초기 script나 cookie로 서버/클라이언트 입력을 맞춥니다.</td></tr><tr><td>RSC와 관련은?</td><td>서버 컴포넌트와 클라이언트 컴포넌트 경계를 명확히 해야 합니다.</td></tr></table>\n<h3>면접에서 말할 증거</h3><p>mismatch 경고 원인 추적, 서버 initial props 정리, mounted guard 적용 전후를 설명합니다.</p>\n<h3>오답/주의점</h3><div class=\"callout warn\"><span class=\"co-label\">주의</span><p>경고를 숨기는 것과 서버/클라이언트 렌더 입력을 맞추는 것은 다릅니다.</p></div>\n</section>\n\n<section id=\"feinterview-q11\">\n<div class=\"ch-head\"><span class=\"ch-code\">FE-11</span><h2>Q. 코드 스플리팅과 번들 최적화는 어떻게 하나요?</h2></div>\n<h3>핵심 개념</h3><p>번들 최적화는 파일 크기를 무조건 줄이는 일이 아니라 초기 화면에 꼭 필요한 JavaScript를 줄이고 필요한 시점에 나눠 받게 하는 일입니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>JavaScript 비용은 다운로드 크기만이 아닙니다. 브라우저는 스크립트를 다운로드하고, 압축을 풀고, parse/compile하고, 실행해야 합니다. 큰 라이브러리가 초기 chunk에 들어오면 네트워크뿐 아니라 메인 스레드도 오래 점유합니다. 코드 스플리팅은 이 비용을 뒤로 미루는 기술이지만, 너무 잘게 나누면 요청 waterfall과 loading state가 늘어납니다. 따라서 “쪼갰다”가 아니라 첫 사용자 행동에 필요한 코드와 나중 행동에 필요한 코드를 구분하는 것이 핵심입니다.</p>\n</div>\n<h3>30초 답변</h3><div class=\"serial-card\">먼저 bundle analyzer로 큰 의존성과 중복을 확인합니다. route-level splitting, dynamic import, tree shaking, 무거운 editor/chart 라이브러리 지연 로딩을 적용하고, split이 너무 잘게 쪼개져 request overhead가 커지지 않는지도 봅니다.</div>\n<h3>원인-결과 흐름</h3>\n<p>큰 라이브러리가 초기 chunk에 들어오면 download뿐 아니라 decompress, parse/compile, execute 비용이 main thread를 점유합니다. route-level splitting과 dynamic import는 첫 화면에 필요 없는 editor/chart 코드를 뒤로 미루지만, 너무 잘게 쪼개면 request waterfall과 fallback 깜빡임이 늘어납니다. preload와 fetchpriority는 LCP 후보를 앞당길 수 있지만 잘못 쓰면 덜 중요한 chunk가 네트워크를 선점하는 priority inversion을 만들 수 있습니다.</p>\n<h3>90초 발화형 답변</h3><p>번들 최적화는 gzip 크기만 줄이는 일이 아니라 초기 사용자 행동에 꼭 필요한 JavaScript 실행 비용을 줄이는 일입니다. 먼저 bundle analyzer로 vendor, polyfill, locale data, icon, chart/editor 라이브러리가 초기 chunk에 들어오는지 확인합니다. 첫 화면에 필요 없는 기능은 route-level splitting이나 사용 액션 기준 dynamic import로 나누고, loading fallback이 사용자 흐름을 끊지 않는지도 봅니다. preload와 fetchpriority는 LCP 이미지나 핵심 font처럼 중요한 자원에만 제한적으로 쓰고, 잘못된 priority가 다른 critical request를 밀어내지 않는지 waterfall로 확인합니다. 최종적으로는 chunk 수, cache hit, parse/compile long task, LCP/INP 변화를 같이 봅니다.</p>\n<h3>실패 모드</h3>\n<p>코드를 너무 잘게 나누면 초기 bundle은 작아져도 runtime waterfall이 늘어 사용자가 클릭한 뒤 더 오래 기다릴 수 있습니다. fetchpriority나 preload를 남용하면 중요하지 않은 자원이 먼저 받아져 LCP가 늦어지는 priority inversion이 생길 수 있습니다.</p>\n<h3>검증 증거</h3>\n<p>bundle analyzer 리포트, chunk waterfall, parse/compile long task, route-level splitting 전후 LCP/INP, preload/fetchpriority 적용 전후 network priority, cache hit 변화를 증거로 제시합니다.</p>\n<h3>압박 질문 방어</h3>\n<p>“gzip 크기를 줄이면 끝인가요?”에는 JavaScript는 parse/compile과 execute 비용도 있어서 main thread long task를 같이 봐야 한다고 답합니다. “dynamic import는 많이 할수록 좋은가요?”에는 request overhead와 fallback UX 때문에 사용자 흐름 기준으로 나눈다고 답합니다.</p>\n<h3>꼬리질문</h3><table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>dynamic import 기준은?</td><td>초기 화면에 필요 없고 크거나 특정 액션에서만 필요한 기능입니다.</td></tr><tr><td>tree shaking 실패는?</td><td>sideEffects, ESM/CJS, import 방식, barrel export를 확인합니다.</td></tr><tr><td>너무 많이 쪼개면?</td><td>요청 수와 waterfall이 늘 수 있어 실제 네트워크에서 확인합니다.</td></tr></table>\n<h3>면접에서 말할 증거</h3><p>번들 분석 리포트, chunk 변화, LCP/TBT 변화, lazy loading fallback UX를 제시합니다.</p>\n<h3>오답/주의점</h3><div class=\"callout warn\"><span class=\"co-label\">주의</span><p>gzip 크기만 말하지 말고 실행 비용과 long task까지 같이 봐야 합니다.</p></div>\n</section>\n\n<section id=\"feinterview-q12\">\n<div class=\"ch-head\"><span class=\"ch-code\">FE-12</span><h2>Q. 디자인 시스템은 왜 중요하고 어떻게 운영하나요?</h2></div>\n<h3>핵심 개념</h3><p>디자인 시스템은 예쁜 컴포넌트 모음이 아니라 제품 UI의 일관성, 접근성, 유지보수, 개발 속도를 관리하는 계약입니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>디자인 시스템의 본질은 반복되는 의사결정을 줄이는 것입니다. 색상 토큰은 단순 팔레트가 아니라 상태와 의미의 계약이고, 컴포넌트 API는 제품 팀이 어떤 변형을 허용할지 정하는 경계입니다. 버튼에 <code>primary</code>, <code>danger</code>, <code>loading</code>, <code>disabled</code>가 있다면 각각의 시각 상태뿐 아니라 접근성 이름, focus, pointer event, submit 중복 방지까지 포함해야 합니다. 그래서 디자인 시스템 운영은 UI를 예쁘게 통일하는 일이 아니라 변경 비용과 오용 가능성을 낮추는 일입니다.</p>\n</div>\n<h3>30초 답변</h3><div class=\"serial-card\">토큰, 컴포넌트, 패턴, 문서, 사용 기준이 함께 있어야 디자인 시스템입니다. 버튼 하나도 색상, 상태, 접근성, 로딩, 비활성, 권한 상태가 정의되어야 실제 제품에서 재사용 가능합니다.</div>\n<h3>90초 답변</h3><p>운영에서는 컴포넌트 API를 안정적으로 유지하고, 변형이 늘어날 때 토큰과 variant 체계로 흡수할지 별도 컴포넌트로 나눌지 판단해야 합니다. Storybook은 시각 문서뿐 아니라 상태 조합, 접근성, regression 확인 도구가 됩니다. 시스템이 과하면 제품 속도를 막을 수 있으므로 자주 반복되는 문제부터 표준화합니다.</p>\n<h3>꼬리질문</h3><table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>토큰은 왜?</td><td>색상, 간격, typography 같은 결정을 코드와 디자인에서 일관되게 쓰기 위해서입니다.</td></tr><tr><td>컴포넌트 API 기준은?</td><td>제품 사용 사례, 접근성, 확장 가능성, 오용 방지를 기준으로 잡습니다.</td></tr><tr><td>언제 과한가요?</td><td>사용 사례가 적고 변화가 큰 영역을 먼저 추상화하면 비용이 큽니다.</td></tr></table>\n<h3>면접에서 말할 증거</h3><p>Storybook 문서, variant 정리 전후, 중복 UI 제거, 접근성 체크 자동화 사례를 말합니다.</p>\n<h3>오답/주의점</h3><div class=\"callout warn\"><span class=\"co-label\">주의</span><p>디자인 시스템을 UI 라이브러리 도입과 같은 말로 쓰면 얕습니다.</p></div>\n</section>\n\n<section id=\"feinterview-q13\">\n<div class=\"ch-head\"><span class=\"ch-code\">FE-13</span><h2>Q. 대용량 grid나 복잡한 입력 UI 성능은 어떻게 다루나요?</h2></div>\n<h3>핵심 개념</h3><p>대용량 입력 UI는 렌더링 비용, validation 비용, 편집 상태, 저장 실패 복구가 결합된 문제입니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>대용량 grid가 느린 이유는 row가 많아서만이 아닙니다. 한 셀을 수정했는데 전체 row 배열, column definition, cell renderer props가 모두 새 참조가 되면 React는 넓은 범위를 다시 계산합니다. 또한 validation을 매 입력마다 전체 데이터에 대해 돌리면 입력 지연이 생깁니다. grid는 “표”가 아니라 작은 form 수천 개가 모인 시스템이므로 원본, draft, error, dirty state, focus, selection, 서버 저장 상태를 분리해야 합니다.</p>\n</div>\n<h3>30초 답변</h3><div class=\"serial-card\">virtualization으로 보이는 row만 렌더링하고, 서버 원본과 draft, validation error, dirty row를 분리합니다. cell edit마다 전체 데이터를 새로 만들지 않고 변경분 중심으로 관리하며, 무거운 validation은 debounce나 submit 단계로 나눕니다.</div>\n<h3>원인-결과 흐름</h3>\n<p>cell edit가 발생할 때 전체 rows 배열을 새로 만들고 column definition이나 cell renderer props도 매번 새 참조가 되면 row/cell memoization 실패가 발생합니다. 그 결과 보이지 않는 cell까지 render scheduling 대상이 되고, commit과 layout/paint 비용이 커져 입력 지연이 생깁니다. 여기에 validation을 매 key stroke마다 전체 row에 대해 돌리면 IME 입력, focus 유지, 스크롤 sync까지 흔들릴 수 있습니다. 그래서 draft를 row 또는 cell 단위로 분리하고, stable columns, virtualization, overscan, batch validation, 필요 시 worker offloading을 함께 설계합니다.</p>\n<p>정리하면 cell edit → rows 배열 전체 교체 → memoization 실패 → virtualization으로 렌더링 범위 제한 → IME와 focus 유지 검증 → 무거운 validation의 worker offloading 순서로 원인과 대응을 연결합니다.</p>\n<h3>90초 발화형 답변</h3><p>대용량 grid는 row 수가 많아서만 느린 것이 아니라 한 셀 변경이 얼마나 넓게 전파되는지가 중요합니다. 예를 들어 cell edit 때 rows 배열 전체를 새로 만들면 각 row props가 바뀌고 memoization이 깨져 수천 개 cell이 다시 렌더링될 수 있습니다. column definition이 렌더마다 새 객체가 되는 경우도 cell renderer를 불필요하게 깨웁니다. 저는 서버 원본과 draft, dirty row, validation error를 분리하고, 보이는 영역은 virtualization과 적절한 overscan으로 제한합니다. dynamic row height나 pinned column, scroll sync가 있으면 virtualization이 더 어려워지므로 focus와 keyboard navigation까지 같이 테스트합니다. Excel 업로드나 대량 validation은 parse, mapping, preview, validation, submit 단계로 나누고, 무거운 검증은 debounce나 submit 단계 또는 worker offloading으로 분리합니다.</p>\n<h3>실패 모드</h3>\n<p>virtualization만 넣으면 접근성, 검색, focus 이동, IME 조합 입력, 스크롤 복원 문제가 새로 생길 수 있습니다. 저장 실패를 row/cell 단위로 매핑하지 않으면 사용자는 어떤 값을 고쳐야 하는지 알 수 없고, 전체 재시도만 남습니다.</p>\n<h3>검증 증거</h3>\n<p>React Profiler의 row render count, Chrome Performance의 input long task, 스크롤 FPS, commit duration, IME 입력 재현, focus 유지 테스트, row 단위 오류 매핑 화면을 증거로 제시합니다.</p>\n<h3>압박 질문 방어</h3>\n<p>“가상 스크롤을 쓰면 끝 아닌가요?”에는 보이는 row 수는 줄지만 state 전파, validation 비용, focus/접근성 문제가 남는다고 답합니다. “라이브러리 쓰면 해결되나요?”에는 라이브러리는 렌더링 도구이고 domain row, draft, validation, 저장 실패 복구 모델은 직접 설계해야 한다고 답합니다.</p>\n<h3>꼬리질문</h3><table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>virtualization 단점은?</td><td>접근성, dynamic height, focus 이동, 검색/스크롤 복원이 어려울 수 있습니다.</td></tr><tr><td>validation 위치는?</td><td>cell, row, submit, server 단계로 나눕니다.</td></tr><tr><td>저장 실패는?</td><td>row/cell별 오류와 재시도 대상을 명확히 보여줍니다.</td></tr></table>\n<h3>면접에서 말할 증거</h3><p>렌더링 횟수, 스크롤 FPS, 변경분 상태 구조, row 단위 오류 매핑 화면을 준비합니다.</p>\n<h3>오답/주의점</h3><div class=\"callout warn\"><span class=\"co-label\">주의</span><p>Grid 라이브러리 이름보다 상태 구조와 검증 경계가 핵심입니다.</p></div>\n</section>\n\n<section id=\"feinterview-q14\">\n<div class=\"ch-head\"><span class=\"ch-code\">FE-14</span><h2>Q. React Flow, Canvas, SVG, DOM 렌더링 차이는 어떻게 설명하나요?</h2></div>\n<h3>핵심 개념</h3><p>렌더링 기술은 표현력, 상호작용, 접근성, 대량 렌더링, hit testing, 개발 복잡도의 trade-off로 선택합니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>DOM과 SVG는 브라우저가 각 요소를 노드로 관리하므로 스타일링, 접근성, 이벤트 위임이 쉽습니다. 대신 노드 수가 많아지면 style calculation, layout, paint 대상이 늘어납니다. Canvas는 픽셀 버퍼에 직접 그리는 방식이라 많은 점이나 도형을 빠르게 그릴 수 있지만, 브라우저가 개별 도형의 의미를 알지 못합니다. 그래서 hit testing, focus, screen reader 대응, 부분 업데이트를 개발자가 직접 설계해야 합니다. 선택 기준은 “빠른가”가 아니라 “브라우저에게 맡길 일을 어디까지 직접 할 것인가”입니다.</p>\n</div>\n<h3>30초 답변</h3><div class=\"serial-card\">DOM은 접근성과 일반 UI 구성에 강하고, SVG는 벡터 도형과 연결선 표현에 좋으며, Canvas는 많은 요소를 직접 그릴 때 유리합니다. React Flow 같은 라이브러리는 graph UI 생산성을 주지만 node/edge 상태와 렌더링 최적화를 이해해야 합니다.</div>\n<h3>원인-결과 흐름</h3>\n<p>DOM과 SVG는 브라우저가 각 요소의 의미, style, event, focus를 관리하므로 접근성과 상호작용이 쉽지만 노드 수와 path 수가 많아지면 style calculation과 paint 비용이 늘어납니다. Canvas는 픽셀 버퍼에 직접 그리므로 많은 점과 도형을 빠르게 그릴 수 있지만 브라우저가 개별 도형의 의미를 잃습니다. 그래서 dirty rectangle으로 다시 그릴 영역을 줄이고, hit map으로 좌표와 도형을 매핑하며, device pixel ratio를 반영해 선명도를 맞추고, 필요하면 WebGL로 전환하거나 DOM overlay로 접근성/입력을 보완해야 합니다.</p>\n<h3>90초 발화형 답변</h3><p>렌더링 방식을 고를 때는 빠른지만 보지 않고 브라우저에게 맡길 책임과 우리가 직접 구현할 책임을 나눕니다. DOM은 접근성, focus, text selection, form interaction에 강해서 일반 UI에 적합합니다. SVG는 연결선, 확대/축소, path styling에 좋지만 path 수가 많아지면 paint 비용이 커질 수 있습니다. Canvas는 대량 렌더링에 유리하지만 개별 요소의 hit testing, keyboard focus, screen reader 대체 구조, dirty rectangle, device pixel ratio 보정을 직접 설계해야 합니다. 요소 수와 animation이 더 커지면 WebGL을 검토하고, 입력 UI나 tooltip은 DOM overlay로 섞는 전략도 씁니다. React Flow는 생산성을 주지만 domain graph와 view graph, node/edge 상태 안정성, drag 중 업데이트 범위를 별도로 설계해야 합니다.</p>\n<h3>실패 모드</h3>\n<p>Canvas를 쓰면 화면은 빨라져도 접근성, 테스트, hit testing, text selection이 사라질 수 있습니다. SVG나 DOM을 너무 많은 노드로 구성하면 layout과 paint가 커져 drag나 zoom이 끊길 수 있습니다.</p>\n<h3>검증 증거</h3>\n<p>노드/path 수 증가별 frame time, Canvas dirty rectangle 적용 전후 redraw 비용, hit map 정확도, device pixel ratio 대응, WebGL 전환 기준, DOM overlay 상호작용 테스트, React Flow drag 중 commit 횟수를 증거로 제시합니다.</p>\n<h3>압박 질문 방어</h3>\n<p>“Canvas가 항상 빠르지 않나요?”에는 그리기 자체는 유리할 수 있지만 hit testing, 접근성, focus, testing 비용을 직접 구현해야 한다고 답합니다. “React Flow 쓰면 그래프 문제는 끝인가요?”에는 저장 가능한 domain graph와 화면용 view graph를 분리해야 한다고 답합니다.</p>\n<h3>꼬리질문</h3><table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>Canvas 접근성은?</td><td>대체 DOM 구조, keyboard interaction, ARIA 보조가 필요합니다.</td></tr><tr><td>React Flow 성능은?</td><td>node props 안정성, selector, memoization, drag 업데이트 범위를 봅니다.</td></tr><tr><td>SVG가 좋은 경우는?</td><td>도형, 연결선, 확대/축소, 스타일 제어가 필요한 경우입니다.</td></tr></table>\n<h3>면접에서 말할 증거</h3><p>노드 수 증가 시 렌더링 비용, node/edge 저장 payload, drag 중 commit 횟수 측정 결과를 말합니다.</p>\n<h3>오답/주의점</h3><div class=\"callout warn\"><span class=\"co-label\">주의</span><p>Canvas가 항상 빠르다는 식의 답변은 위험합니다. 상호작용과 접근성 비용을 같이 말해야 합니다.</p></div>\n</section>\n\n<section id=\"feinterview-q15\">\n<div class=\"ch-head\"><span class=\"ch-code\">FE-15</span><h2>Q. 프론트엔드 장애나 버그는 어떤 순서로 디버깅하나요?</h2></div>\n<h3>핵심 개념</h3><p>디버깅은 추측으로 코드를 바꾸는 일이 아니라 재현 조건, 계층 분리, 증거 수집, 최소 수정, 회귀 검증의 과정입니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>프론트엔드 버그는 같은 증상이라도 원인이 여러 계층에 있을 수 있습니다. 버튼이 안 눌리는 문제는 disabled 조건, overlay, pointer-events, event propagation, 네트워크 pending, 권한 응답, 상태 동기화 중 어디서든 생길 수 있습니다. 그래서 먼저 재현 가능한 입력과 기대 결과를 고정하고, 브라우저 이벤트, React state, API 응답, adapter, 렌더 조건을 한 단계씩 분리합니다. 좋은 디버깅 답변은 “무엇을 고쳤다”보다 “어떤 가설을 어떤 증거로 제거했다”를 보여줍니다.</p>\n</div>\n<h3>30초 답변</h3><div class=\"serial-card\">먼저 재현 조건과 영향 범위를 고정하고 Network, Console, Performance, React state, API 응답을 계층별로 분리합니다. 원인이 확인되면 최소 수정 후 같은 재현 절차와 테스트로 회귀를 막습니다.</div>\n<h3>90초 답변</h3><p>예를 들어 중복 요청이면 사용자 중복 클릭, Strict Mode, effect dependency, remount, query key 중복을 나눠 봅니다. 화면 불일치라면 API response, adapter, store, render condition 순서로 좁힙니다. 운영 이슈에서는 Sentry, 로그, release version, feature flag, 사용자 환경을 함께 확인합니다.</p>\n<h3>꼬리질문</h3><table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>재현이 안 되면?</td><td>로그, 사용자 환경, feature flag, release diff, telemetry를 추가합니다.</td></tr><tr><td>빠른 hotfix는?</td><td>영향 범위와 rollback 가능성을 확인하고 최소 변경으로 대응합니다.</td></tr><tr><td>회귀 방지는?</td><td>재현 테스트, E2E 핵심 경로, monitoring alert를 추가합니다.</td></tr></table>\n<h3>면접에서 말할 증거</h3><p>재현 steps, Network waterfall, Sentry event, release diff, 수정 전후 테스트를 예시로 말합니다.</p>\n<h3>오답/주의점</h3><div class=\"callout warn\"><span class=\"co-label\">주의</span><p>“일단 useEffect dependency를 지웠습니다” 같은 답변은 원인 분석 없이 증상을 숨긴 것으로 들립니다.</p></div>\n</section>\n\n<section id=\"feinterview-q16\">\n<div class=\"ch-head\"><span class=\"ch-code\">FE-16</span><h2>핵심 질문 20선과 답변 훈련</h2></div>\n<p class=\"lede\">아래 질문은 프론트엔드 면접에서 반복적으로 깊이를 확인하는 축입니다. 각 질문은 30초 답변으로 시작하고, 90초 확장에서 trade-off와 검증 방법을 붙입니다.</p>\n<h3>실전 압박 면접 세트</h3>\n<p>이 세트는 질문을 많이 외우기 위한 목록이 아니라, 면접관이 “왜 그렇게 판단했나요?”, “실제로 빨라졌다는 증거가 있나요?”, “언제 쓰면 안 되나요?”라고 물었을 때 답변을 확장하는 훈련입니다.</p>\n<table>\n<tr><th>질문 축</th><th>30초 시작 문장</th><th>90초 확장 포인트</th><th>반드시 말할 증거</th><th>피해야 할 답변</th></tr>\n<tr><td>React 렌더링</td><td>먼저 React render 비용인지 commit 이후 브라우저 비용인지 분리합니다.</td><td>state update, render scheduling, reconciliation, commit, layout/paint를 나누고 memoization이 실패하는 참조 원인을 설명합니다.</td><td>Profiler render reason, commit duration, Performance long task</td><td>React.memo를 붙이면 빨라진다고 단정하기</td></tr>\n<tr><td>웹 성능</td><td>성능은 LCP, INP, CLS 중 어떤 사용자 지표가 나쁜지부터 나눕니다.</td><td>TTFB, render-blocking resource, LCP image, long task, layout box를 waterfall과 field data로 좁힙니다.</td><td>CrUX/RUM p75, Lighthouse, Network waterfall, layout shift entry</td><td>이미지와 번들만 줄였다고 말하기</td></tr>\n<tr><td>접근성</td><td>접근성은 ARIA를 붙이는 일이 아니라 native semantic을 깨지 않는 일입니다.</td><td>accessible name, focus trap, aria-live, roving tabindex, virtualized list/grid의 keyboard 흐름을 설명합니다.</td><td>keyboard-only 녹화, screen reader smoke test, axe 결과</td><td>Lighthouse 점수만으로 충분하다고 말하기</td></tr>\n<tr><td>보안</td><td>프론트 보안은 untrusted source가 어떤 sink로 들어가는지 추적합니다.</td><td>markdown, SVG, URL, DOM sink, Trusted Types, CSP, sanitizer bypass, cookie/token trade-off를 연결합니다.</td><td>negative test, CSP violation report, token storage ADR</td><td>CORS나 UI 숨김을 인가로 설명하기</td></tr>\n<tr><td>대용량 Grid</td><td>Grid는 row 수보다 한 셀 변경이 어디까지 전파되는지가 중요합니다.</td><td>rows 배열 참조, stable columns, virtualization, IME/focus, worker offloading, row 단위 오류 복구를 설명합니다.</td><td>row render count, input p95, 스크롤 FPS, 오류 매핑 화면</td><td>Grid 라이브러리 이름만 말하기</td></tr>\n</table>\n<table>\n<tr><th>축</th><th>핵심 질문 20선</th><th>90초 확장 포인트</th></tr>\n<tr><td>브라우저</td><td>렌더링 파이프라인, reflow/repaint, event loop, HTTP cache, CORS</td><td>측정 도구, 병목 구간, 사용자 체감 지표</td></tr>\n<tr><td>React</td><td>render/commit, memoization, state 위치, effect 의존성, hydration mismatch</td><td>불필요 렌더링 원인과 재현 방법</td></tr>\n<tr><td>성능</td><td>Core Web Vitals, bundle split, image 최적화, virtualization, 대용량 입력</td><td>전후 수치, p95 사용자 경험, 회귀 방지</td></tr>\n<tr><td>품질</td><td>접근성, 보안, 테스트 pyramid, E2E 범위, 디자인 시스템 운영</td><td>자동화 가능한 검증과 사람이 봐야 하는 검증</td></tr>\n</table>\n<h3>구체 질문 20개</h3>\n<table>\n<tr><th>번호</th><th>면접 질문</th><th>답변에서 반드시 연결할 지점</th></tr>\n<tr><td>1</td><td>브라우저 렌더링 파이프라인에서 layout, paint, composite 비용은 어떤 코드 변경에서 달라지나요?</td><td>Performance 탭, layout thrashing, transform/opacity</td></tr>\n<tr><td>2</td><td>React 컴포넌트가 다시 렌더링되는 원인을 어떻게 찾고, 어떤 경우에 memoization을 적용하나요?</td><td>Profiler, props 참조 안정성, 실제 병목</td></tr>\n<tr><td>3</td><td>서버 상태와 form draft를 같은 store에 넣었을 때 어떤 장애가 생길 수 있나요?</td><td>원본/수정본 분리, 취소, 저장 실패 복구</td></tr>\n<tr><td>4</td><td>SSR, SSG, ISR, CSR을 페이지별로 선택할 때 SEO, 개인화, hydration 비용을 어떻게 비교하나요?</td><td>TTFB, cache, 사용자별 데이터, hydration mismatch</td></tr>\n<tr><td>5</td><td>Core Web Vitals 중 LCP, CLS, INP가 각각 나빠졌을 때 어떤 순서로 원인을 좁히나요?</td><td>Network waterfall, long task, 이미지/폰트/레이아웃</td></tr>\n<tr><td>6</td><td>모달 컴포넌트를 접근성 있게 만들려면 focus, keyboard, labeling을 어떻게 설계해야 하나요?</td><td>focus trap, Escape, aria-labelledby, focus return</td></tr>\n<tr><td>7</td><td>XSS가 발생했을 때 localStorage token과 httpOnly cookie 방식은 각각 어떤 피해와 trade-off를 가지나요?</td><td>탈취 가능성, CSRF, SameSite, 서버 인가</td></tr>\n<tr><td>8</td><td>컴포넌트 테스트, 통합 테스트, E2E 테스트를 어떤 기준으로 나누고 중복을 줄이나요?</td><td>위험도, MSW, 핵심 journey, 실패 상태</td></tr>\n<tr><td>9</td><td>hydration mismatch가 시간, locale, localStorage, 인증 상태 때문에 생길 때 어떤 방어를 하나요?</td><td>서버/클라이언트 첫 입력 일치, mounted guard</td></tr>\n<tr><td>10</td><td>bundle analyzer에서 큰 chart/editor 라이브러리를 발견했을 때 어떤 lazy loading 전략을 세우나요?</td><td>route/action split, fallback UX, chunk waterfall</td></tr>\n<tr><td>11</td><td>대용량 grid에서 한 셀 수정이 전체 table 렌더링으로 번지는 원인을 어떻게 줄이나요?</td><td>row/cell memo, stable column, draft 변경분</td></tr>\n<tr><td>12</td><td>Canvas, SVG, DOM, React Flow 중 그래프 UI 구현 방식을 고를 때 어떤 trade-off를 보나요?</td><td>노드 수, 접근성, hit testing, 저장 payload</td></tr>\n<tr><td>13</td><td>Strict Mode에서 effect가 두 번 실행되는 것처럼 보일 때 실제 버그와 개발 모드 검증을 어떻게 구분하나요?</td><td>idempotent effect, cleanup, 중복 요청 방지</td></tr>\n<tr><td>14</td><td>Suspense fallback과 Error Boundary는 각각 어떤 실패나 지연을 처리하고, SSR에서는 무엇이 달라지나요?</td><td>loading/error 경계, streaming SSR, segment fallback</td></tr>\n<tr><td>15</td><td>useTransition과 useDeferredValue는 입력 반응성과 무거운 렌더링 사이에서 어떤 문제를 풀어주나요?</td><td>urgent/non-urgent update, stale 표시, pending state</td></tr>\n<tr><td>16</td><td>CSP nonce/hash와 Trusted Types를 적용해도 sanitizer bypass를 왜 별도로 점검해야 하나요?</td><td>HTML sink, policy, markdown/URL allowlist</td></tr>\n<tr><td>17</td><td>SameSite=Lax 쿠키만으로 CSRF 방어가 충분하지 않은 경우는 언제인가요?</td><td>top-level navigation, legacy browser, origin 검증</td></tr>\n<tr><td>18</td><td>HTTP cache, preload, fetchpriority를 잘못 쓰면 초기 로딩이 왜 더 느려질 수 있나요?</td><td>cache key, stale policy, priority inversion</td></tr>\n<tr><td>19</td><td>디자인 시스템 컴포넌트 API가 제품 요구를 막기 시작하면 어떤 기준으로 확장하거나 분리하나요?</td><td>variant 폭발, 토큰, 접근성 계약</td></tr>\n<tr><td>20</td><td>운영 장애를 재현하지 못할 때 어떤 telemetry와 release diff로 가설을 세우나요?</td><td>Sentry, feature flag, 사용자 환경, rollback</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">압박 꼬리질문</span>\n<p>“그 최적화가 실제로 빨라졌다는 증거는?”, “React.memo를 남발하면 어떤 문제가 생기나요?”, “접근성은 Lighthouse 점수만 보면 되나요?” 같은 질문에 답할 수 있어야 합니다.</p>\n</div>\n<div class=\"callout risk\">\n<span class=\"co-label\">흔한 오답</span>\n<p>기술명만 나열하고 측정 기준을 말하지 못하는 답변, 모든 상태를 전역 상태로 올리는 답변, 성능 개선을 체감이 아닌 감으로 설명하는 답변은 평가가 낮습니다.</p>\n</div>\n</section>\n\n<section id=\"feinterview-react-concurrent-ssr-drill\">\n<div class=\"ch-head\"><span class=\"ch-code\">FE-D1</span><h2>REACT CONCURRENT SSR DRILL</h2></div>\n<p class=\"lede\">React 18 이후 면접에서는 렌더링 최적화보다 “동시성 기능이 사용자 경험과 서버 렌더링 경계에서 어떤 실패를 드러내는가”를 묻는 경우가 많습니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">30초</span>\nStrict Mode는 개발 중 effect cleanup과 idempotency 문제를 드러내고, concurrent rendering은 urgent update와 non-urgent update를 나눠 입력 반응성을 지키는 모델입니다. Suspense는 지연을, Error Boundary는 렌더링 실패를 경계별로 다루며, streaming SSR은 HTML을 segment 단위로 먼저 보내고 준비된 부분을 이어 붙여 초기 표시를 앞당깁니다.\n</div>\n<table>\n<tr><th>키워드</th><th>면접 답변 방향</th><th>주의할 실패</th></tr>\n<tr><td>Strict Mode</td><td>개발 모드에서 render/effect가 반복되어도 깨지지 않도록 effect를 idempotent하게 설계합니다.</td><td>중복 API 요청, 이벤트 리스너 중복 등록, cleanup 누락</td></tr>\n<tr><td>Suspense</td><td>데이터나 코드가 준비되지 않은 구간을 fallback 경계로 나누고, 사용자 흐름별 loading UI를 설계합니다.</td><td>너무 큰 fallback 경계, 화면 전체 blank, waterfall</td></tr>\n<tr><td>Error Boundary</td><td>렌더링 중 throw된 오류를 화면 일부에서 복구하고, 비동기 오류는 별도 상태나 query error로 처리합니다.</td><td>event handler/async 오류를 자동으로 잡는다고 오해</td></tr>\n<tr><td>streaming SSR</td><td>서버가 준비된 HTML을 먼저 보내고 Suspense 경계가 풀리는 순서대로 이어 보내 초기 표시를 앞당깁니다.</td><td>개인화 데이터 cache 혼선, hydration mismatch, fallback 깜빡임</td></tr>\n<tr><td>concurrent rendering</td><td>렌더링이 중단·재시작될 수 있으므로 render phase에 side effect를 두지 않습니다.</td><td>render 중 mutation, 외부 store tearing, 비결정적 값</td></tr>\n<tr><td>useTransition/useDeferredValue</td><td>입력 같은 urgent update와 무거운 목록 렌더링 같은 non-urgent update를 분리합니다.</td><td>pending 상태 미표시, 오래된 결과를 최신처럼 노출</td></tr>\n<tr><td>effect cleanup</td><td>subscription, timer, request, observer는 cleanup에서 해제하고 AbortController로 오래된 요청을 정리합니다.</td><td>메모리 누수, stale response, Strict Mode 중복 증상</td></tr>\n</table>\n<h3>압박 질문</h3>\n<table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>Strict Mode에서 API가 두 번 호출되면 기능을 끄나요?</td><td>끄기보다 effect가 재실행되어도 안전한지 확인하고, 요청 dedupe, cleanup, query cache, AbortController로 설계합니다.</td></tr><tr><td>Suspense와 Error Boundary를 어디에 두나요?</td><td>사용자가 독립적으로 이해하고 복구할 수 있는 화면 경계에 둡니다. 전체 앱을 하나의 fallback으로 가리면 디버깅과 UX가 나빠집니다.</td></tr><tr><td>transition을 쓰면 모든 느린 렌더링이 해결되나요?</td><td>아닙니다. 우선순위를 낮출 뿐이라 실제 계산량, virtualization, memoization, 서버 pagination도 함께 봐야 합니다.</td></tr></table>\n</section>\n\n<section id=\"feinterview-frontend-security-cache-drill\">\n<div class=\"ch-head\"><span class=\"ch-code\">FE-D2</span><h2>FRONTEND SECURITY CACHE DRILL</h2></div>\n<p class=\"lede\">프론트엔드 보안 질문은 XSS/CSRF 암기에서 끝나지 않고, 브라우저 정책과 캐시·리소스 우선순위가 실제 제품 위험에 어떤 영향을 주는지까지 이어집니다.</p>\n<table>\n<tr><th>주제</th><th>답변 포인트</th><th>면접에서 피할 오답</th></tr>\n<tr><td>CSP nonce/hash</td><td>inline script를 전부 막는 대신 서버가 생성한 nonce나 고정 hash로 허용 대상을 좁힙니다.</td><td>CSP만 켜면 XSS가 사라진다고 말하기</td></tr>\n<tr><td>Trusted Types</td><td><code>innerHTML</code> 같은 dangerous sink에 문자열이 직접 들어가지 않도록 policy를 강제합니다.</td><td>타입스크립트 타입과 같은 것으로 오해하기</td></tr>\n<tr><td>sanitizer bypass</td><td>markdown, SVG, URL protocol, DOM clobbering, mutation XSS처럼 sanitizer 설정 우회를 점검합니다.</td><td>라이브러리 이름만 말하고 입력/출력 경계를 설명하지 않기</td></tr>\n<tr><td>token/cookie trade-off</td><td>localStorage token은 XSS 탈취에 약하고, httpOnly cookie는 JS 접근을 막지만 CSRF와 SameSite 정책을 같이 봐야 합니다.</td><td>한 방식이 무조건 안전하다고 단정하기</td></tr>\n<tr><td>SameSite 한계</td><td>Lax는 top-level navigation 예외와 브라우저 차이가 있고, 민감 작업은 CSRF token과 Origin/Referer 검증이 필요합니다.</td><td>SameSite 하나로 CSRF가 끝난다고 답하기</td></tr>\n<tr><td>HTTP cache</td><td>개인화 응답은 private/no-store를 검토하고, 정적 asset은 hash filename과 long max-age로 분리합니다.</td><td>API와 정적 asset 캐시 전략을 섞기</td></tr>\n<tr><td>preload/resource priority</td><td>LCP 이미지, font, critical CSS는 preload/fetchpriority 후보지만 남용하면 중요한 요청을 밀어낼 수 있습니다.</td><td>preload를 많이 넣으면 항상 빨라진다고 말하기</td></tr>\n</table>\n<div class=\"serial-card\">\n<span class=\"sc-label\">90초</span>\n보안과 성능은 분리된 주제가 아닙니다. 인증 응답을 CDN이나 브라우저 cache에 잘못 저장하면 권한 노출이 되고, CSP nonce를 SSR/streaming 환경에서 일관되게 전달하지 못하면 스크립트가 차단됩니다. 반대로 resource priority를 과하게 올리면 실제 LCP 후보가 아닌 자원이 네트워크를 선점해 초기 표시가 늦어질 수 있습니다.\n</div>\n</section>\n\n<section id=\"feinterview-frontend-causal-model\">\n<div class=\"ch-head\"><span class=\"ch-code\">FE-D3</span><h2>프론트엔드 개념 인과관계</h2></div>\n<p class=\"lede\">프론트엔드 면접 답변이 암기처럼 들리는 이유는 React, 브라우저, 네트워크, 보안을 따로 말하기 때문입니다. 실제 사용자 경험은 이 네 계층이 연결되어 만들어집니다.</p>\n<div class=\"serial-card\"><span class=\"sc-label\">FRONTEND CAUSAL MODEL</span>state가 바뀌면 render가 예약되고, render가 비싸거나 같은 참조가 계속 새로 만들어지면 commit과 layout/paint 비용이 커집니다. SSR을 쓰면 첫 HTML은 빨라질 수 있지만 client hydration에서 서버 HTML과 client state가 다르면 mismatch가 생깁니다. cache를 쓰면 재방문은 빨라지지만 개인화 데이터가 섞이면 보안 사고가 됩니다. XSS는 문자열이 DOM sink로 들어갈 때 발생하고, token 저장 방식은 XSS와 CSRF 중 어느 위험을 더 크게 볼지의 선택입니다. 좋은 답변은 “useMemo를 씁니다”가 아니라 “왜 render가 반복되고 어떤 계산/참조/DOM 비용이 실제 병목인지 측정한 뒤 memoization이나 컴포넌트 분리를 선택합니다”로 이어집니다.</div>\n<h3>React rendering chain</h3>\n<p>상위 state가 넓으면 작은 입력 변경도 부모 render를 예약하고, 부모가 새 object/function props를 만들면 child memo가 깨집니다. 이때 reconciliation 범위가 넓어지고 commit이나 browser layout/paint가 커지면 사용자는 입력 지연과 스크롤 끊김으로 체감합니다. 답변은 Profiler로 render reason을 확인하고 state colocating, stable props, virtualization을 어떤 순서로 적용했는지까지 이어져야 합니다.</p>\n<h3>Hydration chain</h3>\n<p>서버 HTML과 client first render 입력이 다르면 hydration warning, 깜빡임, 이벤트 연결 지연이 발생합니다. 시간, random, localStorage, 인증 상태, feature flag처럼 서버와 클라이언트가 다르게 계산하는 값을 분리하고, 필요한 경우 client-only 영역이나 Suspense boundary로 격리해야 합니다.</p>\n<h3>Performance chain</h3>\n<p>큰 JS와 render-blocking resource는 LCP 후보 발견을 늦추고, long task는 사용자의 입력 이후 next paint를 막아 INP를 악화시키며, 늦게 잡히는 layout box는 CLS를 만듭니다. 그래서 성능 답변은 bundle size 하나가 아니라 critical path, main thread, layout stability를 지표별로 나눠야 합니다.</p>\n<h3>Security chain</h3>\n<p>untrusted input이 markdown, SVG, URL, DOM attribute 같은 경로를 지나 sink에 들어가면 XSS나 open redirect가 됩니다. 프론트는 escaping, sanitization, CSP, Trusted Types로 공격면을 줄이고, 서버는 최종 인가와 민감 데이터 응답 정책을 보장해야 합니다.</p>\n<div class=\"callout warn\">\n<span class=\"co-label\">암기 답변 교정</span>\n<p>“React는 virtual DOM이라 빠릅니다”는 위험합니다. React는 변경을 선언적으로 계산하게 해주지만 render 작업 자체는 비용이 있습니다. 빠른지는 state 경계, reconciliation 범위, DOM commit, 브라우저 layout 비용을 어떻게 관리하느냐에 달려 있습니다.</p>\n</div>\n</section>\n\n<section id=\"feinterview-frontend-expert-rendering-model\">\n<div class=\"ch-head\"><span class=\"ch-code\">FE-D4</span><h2>전문가 렌더링 모델: React에서 브라우저까지</h2></div>\n<p class=\"lede\">프론트엔드 고급 면접은 React API를 얼마나 아는지가 아니라, 사용자 입력 하나가 상태 변경, React render, commit, browser layout/paint, network/cache, 보안 경계를 지나며 어떤 비용과 실패를 만드는지 설명할 수 있는지 봅니다.</p>\n<div class=\"serial-card\"><span class=\"sc-label\">EXPERT FRONTEND RENDERING MODEL</span>React에서 state update는 즉시 DOM 변경이 아니라 다음 UI tree를 계산하도록 작업을 예약하는 일입니다. render phase는 순수해야 하며 중단되거나 다시 실행될 수 있습니다. commit phase에서 실제 DOM mutation과 effect 연결이 일어납니다. 그 뒤 브라우저는 style recalculation, layout, paint, composite를 수행합니다. 따라서 “렌더링이 느리다”는 말은 render 계산이 느린지, commit DOM 변경이 큰지, layout이 반복되는지, paint 영역이 큰지, main thread long task가 입력 처리를 막는지로 분해해야 합니다.</div>\n<h3>1. React 최적화의 순서</h3>\n<p>전문가 답변은 <code>useMemo</code>, <code>useCallback</code>, <code>React.memo</code>부터 말하지 않습니다. 먼저 React Profiler로 어떤 컴포넌트가 왜 다시 렌더링되는지 봅니다. parent state 변경 때문에 child가 재실행되는지, props 참조가 매번 바뀌는지, context value가 너무 넓은 범위에 전파되는지, list key가 불안정해 subtree가 remount되는지 확인합니다. 그 다음 state를 더 가까운 곳으로 내리거나, server state와 local draft를 분리하거나, context를 쪼개거나, 실제 비용이 큰 컴포넌트에만 memoization을 적용합니다. memoization은 캐시이므로 dependency가 틀리면 stale value를 만들고, 너무 많이 쓰면 코드 복잡도와 비교 비용이 증가합니다.</p>\n<h3>2. Concurrent rendering과 사용자 입력</h3>\n<p>Concurrent rendering은 모든 일을 자동으로 빠르게 만드는 기능이 아니라 urgent update와 non-urgent update를 나눌 수 있게 하는 모델입니다. 입력 글자가 화면에 바로 반영되어야 하는 update는 urgent이고, 그 입력으로 필터링되는 큰 목록 렌더링은 transition으로 낮은 우선순위를 줄 수 있습니다. 하지만 transition은 계산량을 없애지 않습니다. 목록이 10만 row라면 virtualization, server pagination, worker offloading, incremental rendering 같은 구조적 해법이 필요합니다. 면접에서는 “useTransition을 씁니다”보다 “입력 반응성은 urgent로 유지하고, 결과 목록은 pending 상태를 보여주며, 오래된 결과가 최신처럼 보이지 않게 stale 표시를 둡니다”라고 말해야 합니다.</p>\n<h3>3. SSR, streaming, hydration의 실패 모델</h3>\n<p>SSR은 첫 HTML을 빨리 보여줄 수 있지만, 사용 가능한 앱이 되려면 hydration이 필요합니다. 서버 HTML과 클라이언트 첫 렌더가 다르면 hydration mismatch가 발생합니다. 원인은 시간, random, locale, user agent, localStorage, 인증 상태, AB test, feature flag처럼 서버와 클라이언트 입력이 다른 경우입니다. streaming SSR은 Suspense boundary 단위로 먼저 준비된 HTML을 보내 초기 표시를 앞당기지만, boundary를 잘못 잡으면 중요한 정보가 fallback 뒤에 숨거나 hydration waterfall이 생깁니다. 전문가 답변은 SSR/CSR/SSG 이름을 고르는 것이 아니라 “이 페이지의 SEO, 개인화, freshness, 서버 비용, hydration risk가 무엇인가”를 비교하는 것입니다.</p>\n<h3>4. 브라우저 성능과 Core Web Vitals</h3>\n<p>LCP가 느리면 큰 이미지, font, render-blocking CSS/JS, server TTFB, client hydration 중 어느 단계인지 waterfall로 나눕니다. CLS는 이미지 크기 미지정, late font swap, 광고/동적 영역 삽입처럼 layout box가 뒤늦게 바뀔 때 생깁니다. INP는 사용자의 입력 이후 다음 paint까지 긴 작업이 main thread를 점유할 때 나빠집니다. 그래서 큰 JSON parsing, 무거운 list filtering, synchronous validation, chart layout, third-party script를 long task 관점으로 봐야 합니다. “번들 줄이기”만으로는 INP가 해결되지 않을 수 있습니다.</p>\n<h3>5. 보안과 캐시가 성능과 충돌하는 지점</h3>\n<p>정적 asset은 content hash와 long max-age로 강하게 캐시하는 것이 좋지만, 개인화 API 응답이나 권한별 메뉴 응답은 public cache에 들어가면 사고가 됩니다. httpOnly cookie는 XSS로 token을 읽는 피해를 줄이지만 CSRF와 SameSite, Origin 검증을 함께 봐야 합니다. localStorage token은 구현이 단순하지만 XSS 시 탈취가 쉽습니다. CSP nonce/hash와 Trusted Types는 XSS 피해를 줄이는 강한 장치지만, markdown renderer, sanitizer 설정, URL protocol allowlist가 틀리면 우회될 수 있습니다. 전문가 답변은 “보안은 서버가 합니다”가 아니라 프론트가 어떤 sink와 cache policy를 책임지고, 서버가 어떤 인가와 header를 최종 보장하는지 나눕니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">면접 답변 전환</span>\n<p>“성능 최적화를 했습니다” 대신 “입력 지연의 원인이 React render인지 browser layout인지 먼저 Profiler와 Performance 탭으로 분리했습니다. parent state 변경이 큰 grid를 재렌더링하고 있었고, cell draft state를 row 단위로 분리한 뒤 virtualization을 적용했습니다. 이후 INP와 입력 지연 p95를 비교했고, memoization은 실제 비용이 큰 row renderer에만 적용했습니다”처럼 계층과 증거를 함께 말합니다.</p>\n</div>\n</section>\n\n<section id=\"feinterview-frontend-deep-answer-upgrade\" class=\"answer-card\" data-answer-model=\"definition mechanism tradeoff failure evidence defense\">\n<div class=\"ch-head\"><span class=\"ch-code\">FE-D5</span><h2>DEEP ANSWER MODEL</h2></div>\n<p class=\"lede\">프론트엔드 답변의 질은 API 이름을 많이 말하는지가 아니라 사용자 입력 하나가 React, 브라우저, 네트워크, 보안 경계를 지나며 어떤 비용과 실패를 만드는지 설명하는 능력으로 갈립니다.</p>\n<div class=\"serial-card\"><span class=\"sc-label\">CONCEPT DEPTH</span>정의 → 내부 동작 → trade-off → 실패 모드 → 검증 증거 → FOLLOW-UP DEFENSE 순서로 답합니다. 예를 들어 렌더링 최적화는 “memo를 쓴다”가 아니라 render phase에서 컴포넌트 함수가 재실행되고, commit phase에서 DOM mutation이 발생하며, 이후 browser layout/paint가 실제 사용자 지연을 만든다는 계층으로 설명해야 합니다.</div>\n<table>\n<tr><th>질문</th><th>부실한 답변</th><th>ANSWER UPGRADE TABLE</th></tr>\n<tr><td>React 렌더링 최적화</td><td>useMemo와 React.memo를 사용합니다.</td><td>Profiler로 render phase와 commit phase 비용을 나누고, parent state 범위, context value, key 안정성, list virtualization을 확인한 뒤 실제 병목에만 memoization을 적용합니다.</td></tr>\n<tr><td>웹 성능</td><td>번들을 줄이고 이미지를 최적화합니다.</td><td>LCP는 TTFB, render-blocking resource, LCP image priority를 보고, INP는 main thread long task와 event handler 비용을 봅니다. CLS는 layout box 안정성과 font swap을 확인합니다.</td></tr>\n<tr><td>프론트 보안</td><td>XSS를 막고 token을 안전하게 저장합니다.</td><td>untrusted input이 DOM sink, URL, markdown, SVG로 들어가는 경로를 나누고 CSP nonce/hash, Trusted Types, sanitizer 설정, httpOnly cookie와 CSRF 방어를 함께 설명합니다.</td></tr>\n</table>\n<h3>FOLLOW-UP DEFENSE</h3>\n<table>\n<tr><th>압박 질문</th><th>방어 답변</th><th>COMMON TRAPS</th></tr>\n<tr><td>React.memo를 붙였는데 왜 안 빨라졌나요?</td><td>props 참조가 매번 바뀌거나 실제 병목이 browser layout/paint에 있으면 효과가 제한됩니다. Profiler와 Performance 탭을 같이 봐야 합니다.</td><td>memo를 성능 보장 장치로 말하기</td></tr>\n<tr><td>SSR이면 무조건 빠른가요?</td><td>초기 HTML은 빨라질 수 있지만 hydration 비용과 mismatch 위험이 있습니다. 개인화, cache, server cost까지 비교해야 합니다.</td><td>SSR/CSR을 정답처럼 고르기</td></tr>\n</table>\n<h3>EVIDENCE TO SAY</h3>\n<p>React Profiler commit duration, Chrome Performance long task, Network waterfall, LCP/CLS/INP before-after, bundle analyzer, CSP violation report, QA ticket을 답변 증거로 준비합니다.</p>\n</section>\n\n<section id=\"feinterview-frontend-project-evidence-answer-lab\" class=\"answer-card\" data-answer-model=\"case evidence pressure defense\">\n<div class=\"ch-head\"><span class=\"ch-code\">FE-D6</span><h2>PROJECT EVIDENCE ANSWER LAB</h2></div>\n<p class=\"lede\">좋은 프론트엔드 면접 답변은 “기술을 안다”에서 멈추지 않고, 실제 장애나 개선 과제를 어떤 관찰로 발견했고 어떤 원인 가설을 세웠으며 어떤 지표로 결과를 증명했는지까지 이어집니다. 이 섹션은 경험을 과장하지 않으면서도 시니어답게 말할 수 있도록 사례를 증거 단위로 압축하는 훈련표입니다.</p>\n<div id=\"feinterview-case-evidence-lab\" class=\"serial-card\">\n<span class=\"sc-label\">CASE EVIDENCE LAB</span>\n상황 → 원인 → 조치 → 결과 수치 → 압박 꼬리질문 순서로 정리합니다. 상황은 사용자 영향으로 시작하고, 원인은 브라우저·React·네트워크·접근성·보안 경계 중 어디에서 병목이 생겼는지 설명하며, 조치는 선택하지 않은 대안까지 함께 말합니다.\n</div>\n<table>\n<thead>\n<tr><th>사례</th><th>상황</th><th>원인</th><th>조치</th><th>결과 수치</th><th>압박 꼬리질문</th></tr>\n</thead>\n<tbody>\n<tr>\n<td>React render regression</td>\n<td>검색 입력 중 화면이 끊기고 input p95 지연이 커졌습니다.</td>\n<td>상위 parent state 변경이 목록 전체를 다시 렌더링했고, React Profiler에서 commit duration이 길게 관찰됐습니다.</td>\n<td>상태 소유권을 입력 영역 가까이로 내리고, 행 컴포넌트 memo 기준을 이벤트 핸들러와 파생 데이터까지 포함해 재정리했습니다.</td>\n<td>commit duration과 input p95를 전후 비교하고, 느린 기기 프로파일에서 재현성을 확인했습니다.</td>\n<td>follow-up 1: memo가 오히려 비용이 되지 않았는가. follow-up 2: parent state를 분리해도 데이터 정합성이 깨지지 않는가.</td>\n</tr>\n<tr>\n<td>LCP regression</td>\n<td>릴리즈 뒤 상품 상세의 p75 LCP가 악화되어 검색 유입 전환율이 흔들렸습니다.</td>\n<td>Network waterfall에서 TTFB 증가, render-blocking CSS, 우선순위가 낮은 LCP image 요청이 함께 보였습니다.</td>\n<td>서버 캐시 키를 정리하고 critical CSS를 줄였으며 LCP image preload와 사이즈 예약을 적용했습니다.</td>\n<td>p75 LCP, TTFB, 이미지 요청 시작 시각을 배포 전후로 비교했고, 기준 미달 시 rollback 조건을 릴리즈 체크리스트에 넣었습니다.</td>\n<td>CDN 캐시와 앱 코드 중 무엇이 핵심 원인이었는지, 실험군이 충분했는지 설명할 수 있어야 합니다.</td>\n</tr>\n<tr>\n<td>Modal accessibility</td>\n<td>모달에서 스크린리더 사용자가 제목을 알 수 없고 키보드 사용자가 배경으로 빠져나갔습니다.</td>\n<td>accessible name 연결이 누락됐고 focus trap, Escape 처리, 상태 변경 aria-live 안내가 일관되지 않았습니다.</td>\n<td>dialog 역할, labelledby, 초기 포커스, 복귀 포커스, keyboard-only 탐색 시나리오를 컴포넌트 계약으로 고정했습니다.</td>\n<td>axe 결과와 수동 keyboard-only 테스트, 스크린리더 탐색 로그로 회귀를 막았습니다.</td>\n<td>자동화 도구가 잡지 못하는 접근성 결함을 어떤 사용자 흐름으로 검증했는지 답합니다.</td>\n</tr>\n<tr>\n<td>Markdown XSS</td>\n<td>사용자 작성 Markdown 미리보기에서 링크와 HTML 조합이 보안 리뷰 대상이 됐습니다.</td>\n<td>untrusted source가 sanitizer를 우회해 innerHTML sink에 도달할 가능성이 있었고, URL protocol과 HTML 속성 경계가 불명확했습니다.</td>\n<td>Markdown 파서를 허용 목록 기반으로 제한하고 Trusted Types 정책을 추가했으며 CSP violation 리포트 수집을 배포 환경까지 확장했습니다.</td>\n<td>위험 태그·속성 negative test, sanitizer 단위 테스트, e2e 악성 payload 테스트로 회귀 가능성을 낮췄습니다.</td>\n<td>왜 escape만으로 부족한지, source와 sink 경계를 코드에서 어떻게 강제했는지 설명합니다.</td>\n</tr>\n<tr>\n<td>Grid editing latency</td>\n<td>대량 행 편집 중 IME 조합 입력이 밀리고 스크롤이 끊겼습니다.</td>\n<td>rows 배열 전체 교체와 IME 조합 이벤트 중 동기 검증이 겹치면서 입력이 밀렸습니다.</td>\n<td>행 단위 patch 구조로 변경하고 가상화 overscan을 조정했으며 무거운 검증은 worker offloading으로 분리했습니다.</td>\n<td>row render count, long task 수, IME 입력 p95, 저장 실패율을 함께 보며 UX와 정합성의 균형을 확인했습니다.</td>\n<td>낙관적 업데이트 실패 시 되돌림 정책과 worker 메시지 순서 보장을 어떻게 설계했는지 답합니다.</td>\n</tr>\n</tbody>\n</table>\n<h3>90초 답변 예시</h3>\n<p>“상품 상세 페이지 LCP가 릴리즈 뒤 p75 기준으로 악화됐습니다. 처음에는 이미지 최적화 문제로 봤지만 waterfall을 보니 TTFB 증가와 render-blocking CSS, LCP image 우선순위가 같이 얽혀 있었습니다. 서버 캐시 키를 정리하고 critical CSS 범위를 줄인 뒤 LCP 이미지를 preload했으며, 전후 비교는 p75 LCP와 이미지 요청 시작 시각으로 확인했습니다. 이 과정에서 단순히 평균값만 보지 않고 느린 네트워크 사용자군을 따로 봤고, 기준을 넘으면 rollback하는 조건을 배포 체크에 넣었습니다.”</p>\n<p>“React 렌더링 문제는 useMemo를 넣는 식으로 시작하지 않습니다. 먼저 Profiler로 commit duration과 실제 input p95가 어디에서 증가하는지 확인하고, parent state 변경이 얼마나 넓은 하위 트리를 깨우는지 봅니다. 그 다음 상태 위치, 컴포넌트 경계, key 안정성, 이벤트 핸들러 참조, 파생 데이터 캐시를 순서대로 줄여서 가장 작은 변경으로 사용자 지연을 낮춥니다.”</p>\n<h3>압박 꼬리질문 대응</h3>\n<table>\n<thead><tr><th>질문 유형</th><th>약한 답변</th><th>밀도 높은 답변</th></tr></thead>\n<tbody>\n<tr><td>“그게 진짜 원인인가요?”</td><td>개선 후 빨라졌다고 말합니다.</td><td>가설, 계측 지점, 반례 제거, 전후 지표를 분리해서 설명합니다.</td></tr>\n<tr><td>“왜 그 대안을 선택했나요?”</td><td>그 방식이 좋아서 했다고 말합니다.</td><td>복잡도, 회귀 위험, 팀의 운영 비용, 사용자 영향 범위를 기준으로 선택 이유를 말합니다.</td></tr>\n<tr><td>“실패하면 어떻게 하나요?”</td><td>모니터링한다고 말합니다.</td><td>알림 기준, rollback 조건, feature flag, 데이터 보정 절차를 함께 말합니다.</td></tr>\n<tr><td>“본인이 직접 한 일인가요?”</td><td>프로젝트를 했다고만 말합니다.</td><td>본인이 잡은 문제, 직접 바꾼 코드 경계, 협업한 영역, 배운 점을 분리합니다.</td></tr>\n</tbody>\n</table>\n</section>\n\n<section id=\"doc-jsts\">\n<div class=\"ch-head\"><span class=\"ch-code\">PART</span><h2>JavaScript·TypeScript 면접</h2></div>\n</section>\n\n<section id=\"jsts-q1\">\n<div class=\"ch-head\"><span class=\"ch-code\">JT-01</span><h2>Q. execution context와 lexical environment를 설명해보세요.</h2></div>\n<h3>핵심 개념</h3><p>execution context는 JavaScript 코드가 실행될 때 필요한 환경입니다. 변수 환경, lexical environment, outer reference, this binding이 포함됩니다. lexical environment는 식별자와 값의 매핑, 그리고 바깥 스코프 참조를 가진 구조입니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>execution context는 코드가 실행되는 순간의 작업대이고, lexical environment는 그 작업대에서 식별자를 찾는 사전입니다. 함수 호출이 call stack에 쌓이면 각 호출은 자기 environment를 가지며, 식별자를 찾을 때 현재 환경에서 바깥 환경으로 올라갑니다. hoisting은 선언이 이 환경에 등록되는 방식의 결과이고, TDZ는 등록은 되었지만 초기화 전 접근을 막는 구간입니다.</p>\n</div>\n<h3>30초 답변</h3><div class=\"serial-card\">JavaScript는 함수가 호출될 때 execution context를 만들고 call stack에 쌓습니다. 이 안의 lexical environment가 현재 스코프의 변수와 바깥 스코프 참조를 들고 있어서 scope chain과 closure가 동작합니다.</div>\n<h3>90초 답변</h3><p>면접에서 중요한 점은 “var/let/const가 왜 다르게 보이는가”, “함수 내부에서 바깥 변수를 어떻게 기억하는가”입니다. `let`과 `const`는 lexical environment에 바인딩되지만 초기화 전 TDZ에 있으므로 접근하면 에러가 납니다. closure는 함수가 생성될 때 외부 lexical environment를 참조할 수 있게 유지되는 현상입니다.</p>\n<h3>꼬리질문</h3><table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>hoisting은?</td><td>선언이 environment에 먼저 등록되는 현상으로 설명하되 초기화 차이를 구분합니다.</td></tr><tr><td>TDZ는?</td><td>let/const 선언 전 접근이 허용되지 않는 구간입니다.</td></tr><tr><td>call stack과 관계?</td><td>execution context가 call stack에 쌓이고 완료되면 제거됩니다.</td></tr></table>\n</section>\n\n<section id=\"jsts-q2\">\n<div class=\"ch-head\"><span class=\"ch-code\">JT-02</span><h2>Q. closure는 무엇이고 언제 문제가 되나요?</h2></div>\n<h3>핵심 개념</h3><p>closure는 함수가 선언된 lexical environment를 기억해, 외부 함수 실행이 끝난 뒤에도 그 변수에 접근할 수 있는 구조입니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>closure는 함수가 값 자체를 복사해 들고 있는 것이 아니라 자신이 만들어진 lexical environment에 대한 참조를 유지하는 구조입니다. 그래서 외부 함수 호출이 끝나도 내부 함수가 해당 변수를 읽을 수 있습니다. React의 stale closure는 렌더 시점의 값이 callback에 남아 최신 상태와 어긋나는 문제이므로 dependency, functional update, ref 중 어떤 모델이 맞는지 판단해야 합니다.</p>\n</div>\n<h3>30초 답변</h3><div class=\"serial-card\">closure는 내부 함수가 외부 스코프 변수를 계속 참조할 수 있는 현상입니다. 상태 은닉, callback, React hook에서 자주 쓰이지만 오래된 값을 캡처하는 stale closure나 불필요한 메모리 유지 문제가 생길 수 있습니다.</div>\n<h3>90초 답변</h3><p>React에서 stale closure는 흔한 꼬리질문입니다. effect나 callback이 렌더 당시 값을 캡처했는데 dependency가 빠져 최신 값을 보지 못하는 경우입니다. 해결은 dependency를 정확히 두거나 functional update, ref, state 구조 조정으로 의도를 명확히 하는 것입니다.</p>\n<h3>꼬리질문</h3><table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>메모리 누수와 관계?</td><td>closure가 큰 객체를 계속 참조하면 GC가 회수하지 못할 수 있습니다.</td></tr><tr><td>for loop 문제는?</td><td>var는 함수 스코프라 같은 바인딩을 공유하고 let은 블록 스코프로 매 반복 새 바인딩을 만듭니다.</td></tr><tr><td>React에서?</td><td>event handler와 effect가 렌더 시점의 값을 캡처한다는 점을 말합니다.</td></tr></table>\n</section>\n\n<section id=\"jsts-q3\">\n<div class=\"ch-head\"><span class=\"ch-code\">JT-03</span><h2>Q. prototype, class, this, arrow function을 어떻게 설명하나요?</h2></div>\n<h3>핵심 개념</h3><p>JavaScript 객체는 prototype chain을 통해 속성을 찾습니다. `class`는 prototype 기반 상속을 더 익숙한 문법으로 감싼 형태입니다. `this`는 호출 방식에 따라 결정되고 arrow function은 lexical this를 가집니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>prototype chain은 객체의 속성 조회 규칙입니다. 객체 자신에게 property가 없으면 prototype을 따라 올라가며, class 문법도 이 모델 위에 method를 prototype에 배치하는 문법적 장치입니다. <code>this</code>는 선언 위치가 아니라 호출 형태로 결정되고, arrow function은 자기 <code>this</code>를 만들지 않아 바깥 lexical <code>this</code>를 사용합니다.</p>\n</div>\n<h3>30초 답변</h3><div class=\"serial-card\">객체에서 속성을 찾을 때 자기 자신에 없으면 prototype chain을 따라 올라갑니다. class method는 prototype에 올라가고, arrow function은 자기 this를 만들지 않아 선언된 바깥 this를 사용합니다.</div>\n<h3>90초 답변</h3><p>`this`는 함수가 어디서 선언됐는지가 아니라 어떻게 호출됐는지에 따라 달라집니다. `obj.method()`면 `obj`, 그냥 함수로 호출되면 strict mode에서는 undefined가 됩니다. arrow function은 호출 방식으로 this가 바뀌지 않기 때문에 callback에서 유용하지만 method로 남용하면 prototype 공유 이점이 줄 수 있습니다.</p>\n<h3>꼬리질문</h3><table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>class는 hoisting?</td><td>class 선언도 lexical binding이지만 TDZ가 있어 선언 전 접근할 수 없습니다.</td></tr><tr><td>bind/call/apply?</td><td>this를 명시적으로 지정해 호출하는 방법입니다.</td></tr><tr><td>prototype 오염?</td><td>외부 입력으로 prototype이 변조되면 보안 문제가 됩니다.</td></tr></table>\n</section>\n\n<section id=\"jsts-q4\">\n<div class=\"ch-head\"><span class=\"ch-code\">JT-04</span><h2>Q. event loop, microtask, macrotask를 설명해보세요.</h2></div>\n<h3>핵심 개념</h3><p>JavaScript는 call stack이 비면 event loop가 task queue에서 작업을 가져옵니다. Promise callback은 microtask queue에 들어가고, timer나 IO callback은 macrotask 계열로 다뤄집니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>event loop는 비동기 작업을 병렬로 실행하는 마법이 아니라 call stack이 빈 시점에 예약된 callback을 실행하는 조정 장치입니다. microtask는 현재 task가 끝난 뒤 렌더링이나 다음 task로 넘어가기 전에 비워지는 경향이 있어 Promise callback이 timer보다 먼저 관찰될 수 있습니다. 긴 동기 JavaScript는 queue 순서와 무관하게 입력 처리와 렌더링 자체를 막습니다.</p>\n</div>\n<h3>30초 답변</h3><div class=\"serial-card\">동기 코드는 call stack에서 먼저 실행되고, Promise의 then/await 이후 작업은 microtask로 예약됩니다. microtask는 보통 다음 macrotask보다 먼저 비워지므로 timer보다 Promise callback이 먼저 실행되는 경우가 많습니다.</div>\n<h3>90초 답변</h3><p>실무에서는 long task가 event loop를 막아 클릭 반응과 렌더링을 지연시키는 문제가 중요합니다. 무거운 계산은 chunking, Web Worker, debounce, requestIdleCallback 같은 전략으로 나눌 수 있습니다. Node.js와 브라우저 event loop는 세부 phase가 다르므로 환경도 구분해야 합니다.</p>\n<h3>꼬리질문</h3><table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>async/await는?</td><td>await 이후 코드는 Promise continuation으로 microtask에 예약됩니다.</td></tr><tr><td>rendering과 관계?</td><td>긴 JS task가 브라우저 렌더링과 입력 처리를 막을 수 있습니다.</td></tr><tr><td>queueMicrotask?</td><td>명시적으로 microtask를 예약하는 API입니다.</td></tr></table>\n</section>\n\n<section id=\"jsts-q5\">\n<div class=\"ch-head\"><span class=\"ch-code\">JT-05</span><h2>Q. Promise와 async/await 오류 처리는 어떻게 하나요?</h2></div>\n<h3>핵심 개념</h3><p>Promise는 비동기 작업의 eventual result를 표현합니다. async 함수는 항상 Promise를 반환하고, throw는 rejected Promise가 됩니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>Promise는 지금 값이 아니라 나중에 성공 또는 실패로 확정될 결과를 표현합니다. <code>async</code> 함수의 반환값은 항상 Promise로 감싸지고, 함수 안의 <code>throw</code>는 rejected Promise가 됩니다. 순차 <code>await</code>는 읽기 쉽지만 병렬 가능한 작업까지 직렬화할 수 있으므로 의존 관계가 있는지 먼저 봐야 합니다.</p>\n</div>\n<h3>30초 답변</h3><div class=\"serial-card\">async/await는 Promise를 동기 코드처럼 읽게 해주지만 오류는 반드시 try/catch나 상위 caller에서 처리해야 합니다. 병렬 가능한 작업은 순차 await하지 않고 `Promise.all`을 쓰되, 하나 실패하면 전체가 reject되는 성질도 고려합니다.</div>\n<h3>90초 답변</h3><p>`Promise.allSettled`는 일부 실패를 수집해야 할 때 유용하고, `Promise.race`나 `AbortController`는 timeout/cancel 흐름에서 씁니다. 실무에서는 unhandled rejection, 중복 요청, 오래된 응답이 최신 상태를 덮는 문제가 자주 생기므로 요청 id나 abort, latest-only guard를 둡니다.</p>\n<h3>꼬리질문</h3><table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>Promise.all 실패?</td><td>하나라도 reject되면 전체가 reject됩니다.</td></tr><tr><td>finally는?</td><td>성공/실패와 무관하게 정리 로직에 쓰지만 반환/throw에 주의합니다.</td></tr><tr><td>에러 경계?</td><td>비동기 에러는 React Error Boundary가 자동으로 잡지 못하는 경우가 많습니다.</td></tr></table>\n</section>\n\n<section id=\"jsts-q6\">\n<div class=\"ch-head\"><span class=\"ch-code\">JT-06</span><h2>Q. TypeScript structural typing과 unknown vs any를 설명해보세요.</h2></div>\n<h3>핵심 개념</h3><p>TypeScript는 이름이 아니라 구조가 맞으면 호환되는 structural typing을 사용합니다. `any`는 타입 검사를 끄고, `unknown`은 사용 전에 타입 좁히기를 요구합니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>TypeScript의 타입은 런타임 객체에 붙는 태그가 아니라 컴파일 타임에 값의 사용 가능성을 검증하는 모델입니다. structural typing은 이름이 달라도 필요한 구조가 맞으면 호환된다는 뜻이라 유연하지만 의도치 않은 호환도 생길 수 있습니다. <code>unknown</code>은 외부 입력의 신뢰 경계를 타입으로 표현하고, <code>any</code>는 그 경계를 컴파일러가 더 이상 확인하지 못하게 합니다.</p>\n</div>\n<h3>30초 답변</h3><div class=\"serial-card\">TypeScript는 구조적 타입 시스템이라 필요한 property 구조가 맞으면 호환됩니다. `any`는 타입 안전성을 포기하는 탈출구이고, `unknown`은 어떤 값인지 모른다는 뜻이라 사용 전에 type guard로 좁혀야 합니다.</div>\n<h3>90초 답변</h3><p>API 응답, 외부 JSON, catch error처럼 신뢰할 수 없는 값은 `unknown`으로 받고 runtime validation이나 type guard로 좁히는 편이 안전합니다. `any`를 쓰면 잘못된 property 접근이 컴파일에서 드러나지 않아 타입 시스템의 이점을 잃습니다. `never`는 도달 불가능한 상태나 exhaustive check에 사용됩니다.</p>\n<h3>꼬리질문</h3><table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>structural typing 단점?</td><td>의도와 달리 구조만 맞아 호환될 수 있어 branded type이 필요할 수 있습니다.</td></tr><tr><td>type assertion은?</td><td>컴파일러에게 믿으라고 말하는 것이지 runtime 검증이 아닙니다.</td></tr><tr><td>never는?</td><td>불가능한 타입으로 exhaustive switch 검증에 유용합니다.</td></tr></table>\n</section>\n\n<section id=\"jsts-q7\">\n<div class=\"ch-head\"><span class=\"ch-code\">JT-07</span><h2>Q. generic, union/intersection, type guard, conditional type은 언제 쓰나요?</h2></div>\n<h3>핵심 개념</h3><p>generic은 타입을 매개변수화해 재사용하면서 정보 손실을 줄입니다. union은 여러 가능성 중 하나, intersection은 여러 타입의 결합입니다. conditional type은 타입 수준 조건 분기입니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">개념 해부</span>\n<p>generic은 타입을 추상화하는 장치가 아니라 입력과 출력 사이의 타입 관계를 보존하는 장치입니다. union은 가능한 상태를 닫힌 집합으로 표현하고, discriminant를 두면 분기마다 안전하게 좁힐 수 있습니다. conditional type과 <code>infer</code>는 라이브러리 수준 타입 계산에 강하지만, 팀이 읽을 수 없는 타입은 유지보수 비용이 됩니다.</p>\n</div>\n<h3>30초 답변</h3><div class=\"serial-card\">generic은 입력과 출력의 타입 관계를 보존할 때 씁니다. union은 상태나 응답처럼 여러 케이스가 있을 때 쓰고, type guard로 안전하게 좁힙니다. conditional type은 라이브러리나 공통 타입 유틸에서 타입 관계를 계산할 때 유용합니다.</div>\n<h3>90초 답변</h3><p>예를 들어 API result를 `{ status: \"success\"; data: T } | { status: \"error\"; error: ApiError }` 같은 discriminated union으로 만들면 UI가 성공/실패 상태를 안전하게 처리할 수 있습니다. intersection은 합성에 유용하지만 충돌 property가 생기면 의도가 흐려질 수 있습니다. conditional type은 강력하지만 과하면 팀 이해 비용이 커집니다.</p>\n<h3>꼬리질문</h3><table><tr><th>질문</th><th>답변 방향</th></tr><tr><td>generic 남용?</td><td>타입 관계가 없는데 generic을 쓰면 읽기만 어려워집니다.</td></tr><tr><td>type guard 기준?</td><td>runtime에서 실제로 확인 가능한 property나 predicate를 사용합니다.</td></tr><tr><td>infer는?</td><td>conditional type 안에서 타입 일부를 추론할 때 씁니다.</td></tr></table>\n</section>\n\n<section id=\"jsts-q8\">\n<div class=\"ch-head\"><span class=\"ch-code\">JT-08</span><h2>나쁜 답변 / 개선 답변 / 좋은 답변</h2></div>\n<table>\n<tr><th>질문</th><th>나쁜 답변</th><th>개선 답변</th><th>좋은 답변</th></tr>\n<tr><td>event loop</td><td>비동기를 처리하는 것입니다.</td><td>call stack이 비면 queue의 작업을 실행합니다.</td><td>동기 코드, microtask, macrotask 순서와 long task가 렌더링·입력 반응을 막는 실무 문제까지 설명합니다.</td></tr>\n<tr><td>unknown vs any</td><td>둘 다 아무 타입입니다.</td><td>any는 검사하지 않고 unknown은 좁혀야 합니다.</td><td>외부 입력은 unknown으로 받고 type guard/runtime validation으로 좁혀 타입 안전성과 런타임 신뢰 경계를 함께 지킵니다.</td></tr>\n<tr><td>closure</td><td>함수 안 함수입니다.</td><td>외부 변수를 기억하는 함수입니다.</td><td>lexical environment 참조를 유지하는 구조이며 stale closure, 메모리 유지, React hook dependency 문제로 연결해 설명합니다.</td></tr>\n</table>\n</section>\n\n<section id=\"jsts-q9\">\n<div class=\"ch-head\"><span class=\"ch-code\">JT-09</span><h2>JavaScript 런타임 실패 지도</h2></div>\n<p class=\"lede\">JS 면접에서 전문성은 event loop 정의를 외우는 데서 나오지 않습니다. 브라우저와 Node 런타임에서 실제로 어떤 실패가 생기고, 어떤 증거로 좁히는지 말해야 합니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">JS RUNTIME FAILURE MAP</span>\n“화면이 멈춥니다”는 long task, layout thrashing, microtask starvation, synchronous JSON parsing, 대량 DOM update, memory leak으로 나눠 봅니다. “요청 결과가 꼬입니다”는 stale closure, race between requests, abort 누락, cache key 충돌, optimistic update rollback 누락으로 나눕니다. 언어 지식은 이 현상들을 설명할 때 가치가 있습니다.\n</div>\n<table>\n<tr><th>현상</th><th>관련 개념</th><th>면접에서 말할 증거</th><th>방어 전략</th></tr>\n<tr><td>클릭 반응이 늦음</td><td>call stack, long task, rendering block</td><td>Performance panel, long task, input delay, flame chart</td><td>작업 쪼개기, Web Worker, virtualization, debounce</td></tr>\n<tr><td>Promise가 예상 순서와 다름</td><td>microtask queue, task queue, async continuation</td><td>실행 순서 예제, await 이후 continuation, timer 비교</td><td>순서 의존 제거, explicit await, state machine</td></tr>\n<tr><td>검색 결과가 뒤바뀜</td><td>race condition, stale response, abort signal</td><td>Network waterfall, request id, response arrival order</td><td>AbortController, latest-only guard, query key 설계</td></tr>\n<tr><td>hook 값이 오래됨</td><td>closure, render snapshot, dependency</td><td>렌더 시점 값, dependency diff, callback capture</td><td>dependency 보정, functional update, ref, state 소유권 조정</td></tr>\n<tr><td>메모리가 증가함</td><td>closure retention, listener leak, detached DOM</td><td>heap snapshot, retained path, event listener count</td><td>cleanup, weak reference 검토, cache eviction</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">오답 방지</span>\n<p>“비동기라서 순서가 보장되지 않습니다”는 반만 맞는 답입니다. 어떤 queue에 들어가고, 어떤 상태 업데이트가 경쟁하며, 어떤 요청을 취소하거나 무시해야 하는지까지 설명해야 합니다.</p>\n</div>\n</section>\n\n<section id=\"jsts-q10\">\n<div class=\"ch-head\"><span class=\"ch-code\">JT-10</span><h2>TypeScript 타입 안전 경계</h2></div>\n<p class=\"lede\">TypeScript 면접의 핵심은 타입 문법을 많이 아는 것이 아니라, 컴파일 타임 타입과 런타임 데이터의 경계를 정확히 구분하는 것입니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">TS TYPE SAFETY BOUNDARY</span>\nTypeScript 타입은 빌드 후 사라지므로 외부 API 응답, localStorage, URL query, form input, postMessage, feature flag, 서버 에러 payload는 런타임 검증이 필요합니다. 타입 선언은 “그럴 것”이라는 약속이고, validation은 “실제로 그렇다”는 확인입니다.\n</div>\n<table>\n<tr><th>경계</th><th>위험</th><th>전문적인 답변</th></tr>\n<tr><td>API response</td><td>nullable, enum 추가, field rename</td><td><code>unknown</code>으로 받고 schema validation 또는 adapter에서 view model로 변환합니다.</td></tr>\n<tr><td>form input</td><td>문자열 기반 입력, 숫자/날짜 파싱 오류</td><td>입력 타입, 파서, domain validator를 분리하고 오류 path를 유지합니다.</td></tr>\n<tr><td>URL query</td><td>없는 값, 배열/단일 값 혼재, 잘못된 enum</td><td>decode layer에서 기본값과 허용값을 명시합니다.</td></tr>\n<tr><td>localStorage</td><td>오래된 schema, 사용자가 수정한 값</td><td>versioning, migration, validation 실패 시 fallback을 둡니다.</td></tr>\n<tr><td>library type</td><td>너무 넓은 type, 잘못된 assertion</td><td>wrapper와 branded type으로 도메인 불변식을 보강합니다.</td></tr>\n</table>\n<h3>면접에서 말할 증거</h3>\n<p>API adapter, discriminated union 상태 모델, exhaustive switch, type guard, runtime schema, <code>unknown</code> 사용 기준, <code>any</code> 격리 위치를 말합니다.</p>\n<div class=\"callout risk\">\n<span class=\"co-label\">흔한 오답</span>\n<p>“TypeScript라 런타임 오류가 줄어듭니다”에서 멈추면 얕습니다. TypeScript는 신뢰할 수 없는 입력을 자동 검증하지 않으므로, 외부 경계마다 validation과 fallback을 설계해야 합니다.</p>\n</div>\n</section>\n\n<section id=\"jsts-typescript-advanced-boundary\">\n<div class=\"ch-head\"><span class=\"ch-code\">JT-D1</span><h2>TYPESCRIPT ADVANCED BOUNDARY</h2></div>\n<p class=\"lede\">고급 TypeScript 면접은 타입 퍼즐을 푸는 자리가 아니라, 컴파일러가 보장하는 영역과 런타임 검증이 필요한 영역을 정확히 나누는지 확인하는 자리입니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">30초</span>\n<code>satisfies</code>는 값의 구체 타입을 유지하면서 계약을 검사하고, <code>as const</code>는 literal과 readonly 추론을 고정합니다. excess property check는 객체 literal에서 오타를 잡아주지만 변수에 담기는 순간 약해질 수 있고, variance와 branded type은 구조적 타입 시스템의 의도치 않은 호환을 줄이는 도구입니다. strict flags와 runtime schema validation은 외부 입력 경계에서 타입 안전성을 실제 안정성으로 연결합니다.\n</div>\n<table>\n<tr><th>키워드</th><th>전문적인 답변</th><th>실무 경계</th></tr>\n<tr><td>satisfies</td><td>객체가 특정 계약을 만족하는지 검사하되, 값 자체의 literal 타입 정보는 잃지 않습니다.</td><td>설정 객체, route map, i18n message map에서 키 오타와 값 추론을 함께 잡습니다.</td></tr>\n<tr><td>as const</td><td>literal widening을 막고 readonly tuple/object로 추론하게 합니다.</td><td>상수 enum 대체, discriminated union source, 허용값 목록에 유용합니다.</td></tr>\n<tr><td>excess property check</td><td>객체 literal을 직접 대입할 때 여분 속성을 잡지만, 중간 변수나 assertion으로 우회될 수 있습니다.</td><td>API payload builder와 config 생성 함수에서 오타를 잡는 보조 장치로 봅니다.</td></tr>\n<tr><td>variance</td><td>타입 매개변수가 입력/출력 위치에서 어떻게 호환되는지 설명합니다.</td><td>callback, event handler, generic container, readonly collection API 설계에서 중요합니다.</td></tr>\n<tr><td>branded type</td><td>구조가 같은 string/number라도 도메인 의미가 다르면 브랜드를 붙여 섞이지 않게 합니다.</td><td>UserId, OrderId, ISODate, SanitizedHtml처럼 값의 출처나 검증 상태를 표현합니다.</td></tr>\n<tr><td>strict flags</td><td><code>strictNullChecks</code>, <code>noUncheckedIndexedAccess</code>, <code>exactOptionalPropertyTypes</code> 같은 옵션으로 암묵적 빈틈을 줄입니다.</td><td>마이그레이션은 한 번에 켜기보다 hot path와 adapter부터 단계적으로 좁힙니다.</td></tr>\n<tr><td>runtime schema validation</td><td>TypeScript 타입은 런타임에 사라지므로 외부 JSON은 Zod, Valibot, io-ts 같은 schema 또는 직접 validator로 확인합니다.</td><td>API, URL query, localStorage, postMessage, feature flag, server error payload가 대상입니다.</td></tr>\n</table>\n<h3>구체 질문</h3>\n<table>\n<tr><th>질문</th><th>답변 방향</th></tr>\n<tr><td><code>satisfies</code>와 type annotation은 설정 객체의 추론 결과에서 무엇이 달라지나요?</td><td>계약 검사는 하되 literal key/value 정보가 유지되는 점을 예로 듭니다.</td></tr>\n<tr><td><code>as const</code>를 남용하면 어떤 유지보수 문제가 생기나요?</td><td>readonly 확산, 지나치게 좁은 타입, 불필요한 assertion을 구분합니다.</td></tr>\n<tr><td>excess property check가 중간 변수에서 약해지는 이유를 어떻게 설명하나요?</td><td>객체 literal freshness와 structural typing의 차이를 말합니다.</td></tr>\n<tr><td>함수 parameter 타입에서 variance가 왜 callback 안정성과 연결되나요?</td><td>더 좁은 입력만 처리하는 함수를 넓은 자리로 넘길 때의 위험을 설명합니다.</td></tr>\n<tr><td>branded type은 런타임 검증을 대체하나요?</td><td>대체하지 않으며 검증 후 값에 타입 의미를 부여하는 방식이라고 답합니다.</td></tr>\n<tr><td><code>noUncheckedIndexedAccess</code>를 켜면 어떤 코드가 드러나고 어떻게 고치나요?</td><td>배열/record 접근 결과가 undefined일 수 있음을 처리합니다.</td></tr>\n<tr><td>API 응답 타입을 생성했는데도 runtime schema validation이 필요한 이유는 무엇인가요?</td><td>서버 배포 차이, nullable, enum 추가, 악성/오염 데이터 가능성을 듭니다.</td></tr>\n<tr><td>strict flag를 기존 프로젝트에 도입할 때 어떤 순서로 위험을 줄이나요?</td><td>adapter, shared utility, domain model부터 좁히고 any 격리 목록을 관리합니다.</td></tr>\n<tr><td>외부 입력을 <code>unknown</code>으로 받은 뒤 view model로 변환하는 adapter의 장점은 무엇인가요?</td><td>검증, 기본값, 오류 path, UI 타입 분리를 한 곳에 모을 수 있습니다.</td></tr>\n<tr><td>타입 assertion이 꼭 필요한 경우와 위험한 경우를 어떻게 구분하나요?</td><td>런타임 근거가 있는 좁히기인지, 컴파일러 경고를 숨기는지로 구분합니다.</td></tr>\n</table>\n<div class=\"callout risk\">\n<span class=\"co-label\">흔한 오답</span>\n<p>“TypeScript가 있으니 API 응답은 안전합니다”라고 말하면 위험합니다. 타입은 신뢰 경계 안쪽의 개발자 계약이고, 네트워크·저장소·브라우저 메시지 경계에서는 runtime schema validation으로 실제 값을 확인해야 합니다.</p>\n</div>\n</section>\n\n<section id=\"doc-personalfe\">\n<div class=\"ch-head\"><span class=\"ch-code\">PART</span><h2>프론트엔드 개발자 대응</h2></div>\n</section>\n\n<section id=\"personalfe-ch1\">\n<div class=\"ch-head\"><span class=\"ch-code\">FE-PER-00</span><h2>성장 서사</h2></div>\n<div class=\"serial-card\"><span class=\"sc-label\">STORY</span>초기에는 JavaScript·jQuery·Vue 기반으로 어드민 UI와 에너지 서비스의 지도, 차트, 소셜 공유, 반응형 웹을 구현하며 화면 구조와 데이터 시각화 경험을 쌓았습니다. 이후 React/Next/TypeScript 기반 프로젝트에서 인증, 상태관리, 복잡한 Form, Data Grid, i18n, 성능 최적화, 배포까지 맡으며 제품형 프론트엔드 역량으로 확장했습니다.</div>\n<table>\n<tr><th>시기</th><th>기술</th><th>면접에서의 의미</th></tr>\n<tr><td>초기 UI 구현</td><td>JavaScript, jQuery, HTML/CSS, SCSS, Vue, Quasar</td><td>프레임워크 이전의 DOM, 스타일링, 화면 구조 이해가 있습니다.</td></tr>\n<tr><td>에너지 서비스 화면 확장</td><td>Vue3, Chart.js, Kakao Map, Firebase</td><td>지도·차트·소셜 공유·정적 배포 같은 사용자 경험을 다뤘습니다.</td></tr>\n<tr><td>React 실무</td><td>React, MUI, Tailwind, Context API, Redux Toolkit</td><td>대규모 화면 상태와 컴포넌트 구조를 다뤘습니다.</td></tr>\n<tr><td>Next/TypeScript</td><td>Next.js, TypeScript, Jotai, Lingui, SEO/AEO</td><td>타입 안정성, 성능, 검색 노출, 다국어 운영까지 확장했습니다.</td></tr>\n<tr><td>모바일</td><td>React Native, Expo, redux-saga, d3</td><td>웹을 넘어 앱의 상태, 네비게이션, 실시간 갱신 경험이 있습니다.</td></tr>\n</table>\n</section>\n\n<section id=\"personalfe-ch2\">\n<div class=\"ch-head\"><span class=\"ch-code\">FE-PER-01</span><h2>핵심 강점</h2></div>\n<table>\n<tr><th>강점</th><th>증거 프로젝트</th><th>답변 키워드</th></tr>\n<tr><td>복잡한 업무 UI</td><td>산업 데이터 플랫폼, 관리자 콘솔</td><td>Data Grid, Form validation, 권한, Excel/PDF, loading/empty/error</td></tr>\n<tr><td>데이터 시각화</td><td>거래형 서비스, 에너지 앱, 이전 Vue 서비스</td><td>Chart.js, d3, Recharts, 금액·수량 표기, 대시보드</td></tr>\n<tr><td>지도·위치 UI</td><td>React 웹, Vue 서비스</td><td>Google Map, Kakao Map, 주소 검색, 지도 컴포넌트 분리</td></tr>\n<tr><td>국제화</td><td>3-web 서비스, 가상자산 서비스, 기업 웹사이트</td><td>i18n, Lingui, locale, timezone, 번역 사전, 빈 메시지 검출</td></tr>\n<tr><td>성능 최적화</td><td>기업 웹사이트</td><td>next/Image, dynamic import, bundle analyzer, preload, CLS 방지</td></tr>\n<tr><td>검색 노출</td><td>기업 웹사이트</td><td>SEO/AEO, OpenGraph, sitemap, robots, 구조화 데이터</td></tr>\n</table>\n</section>\n\n<section id=\"personalfe-ch3\">\n<div class=\"ch-head\"><span class=\"ch-code\">FE-PER-02</span><h2>대표 답변</h2></div>\n<h3>Q. 가장 자신 있는 프론트엔드 경험은 무엇인가요?</h3>\n<div class=\"serial-card\"><span class=\"sc-label\">30초</span>복잡한 업무 UI를 안정적으로 만드는 경험이 가장 강합니다. 대량 데이터 입력, Data Grid, Form validation, Excel/PDF, 권한별 화면, 인증 만료 같은 흐름을 다뤘고, 단순히 화면을 그리는 것보다 사용자가 실패했을 때 어떻게 복구할지와 서버 API 계약을 함께 보며 구현했습니다.</div>\n<h3>Q. 성능 최적화 경험을 설명해보세요.</h3>\n<div class=\"serial-card\"><span class=\"sc-label\">90초</span>기업 웹사이트에서 이미지와 번들, 폰트 로딩을 중심으로 성능을 개선했습니다. 전체 이미지를 next/Image로 바꾸고 명시적 크기를 지정해 layout shift를 줄였고, dynamic import와 bundle analyzer로 초기 번들에 들어갈 필요가 없는 의존성을 분리했습니다. 폰트 preload와 blur placeholder도 적용했습니다. 정확한 수치가 남아 있지 않은 부분은 과장하지 않고, 어떤 병목을 어떤 구조로 줄였는지 중심으로 설명합니다.</div>\n<h3>Q. i18n 경험은 어떤 수준인가요?</h3>\n<div class=\"serial-card\"><span class=\"sc-label\">90초</span>단순 문자열 치환보다 locale별 날짜, 통화, 메시지 누락, 언어별 리소스 관리까지 경험했습니다. React 서비스에서는 공통 라벨 hook과 번역 사전을 정리했고, Next.js 서비스에서는 Lingui 기반으로 한·영·일 메시지를 운영하며 빈 메시지 검출 스크립트를 빌드 흐름에 연결했습니다.</div>\n</section>\n\n<section id=\"personalfe-ch4\">\n<div class=\"ch-head\"><span class=\"ch-code\">FE-PER-03</span><h2>압박 질문</h2></div>\n<table>\n<tr><th>질문</th><th>답변 방향</th></tr>\n<tr><td>React만 오래 한 게 아니라 깊이도 있나요?</td><td>상태 위치, 서버 상태와 UI 상태 분리, 렌더링 비용, Form 제어, 인증 흐름, 성능 측정 기준으로 답합니다.</td></tr>\n<tr><td>정량 성능 수치가 있나요?</td><td>없는 것은 없다고 말하고, 대신 병목 가설, 변경 구조, 재현 조건, 앞으로 측정할 지표를 말합니다.</td></tr>\n<tr><td>프론트엔드만 하면 서버 이해가 약하지 않나요?</td><td>서버 구현은 경계가 있지만 API 계약, 오류 응답, 인증 만료, pagination/filter, 권한 요구사항은 실무에서 계속 다뤘다고 설명합니다.</td></tr>\n<tr><td>Vue와 jQuery 경험은 오래된 것 아닌가요?</td><td>오히려 프레임워크 변화 속에서도 DOM, 스타일링, 사용자 흐름을 이해하고 React/Next로 확장한 성장 서사로 연결합니다.</td></tr>\n</table>\n</section>\n\n<section id=\"personalfe-ch5\">\n<div class=\"ch-head\"><span class=\"ch-code\">FE-PER-04</span><h2>포트폴리오 문장</h2></div>\n<div class=\"serial-card\"><span class=\"sc-label\">RESUME SUMMARY</span>React/Next/TypeScript 기반으로 B2B 어드민, 거래형 서비스, 기업 웹사이트, React Native 앱을 개발했습니다. Data Grid, 복잡한 Form, 인증·권한, i18n, 지도·차트, 성능 최적화, SEO/AEO, 파일 업로드/다운로드 같은 제품 핵심 흐름을 다뤘고, 화면 구현을 넘어 API 계약과 실패 복구까지 고려하는 프론트엔드 개발을 지향합니다.</div>\n<h3>대체 증거</h3>\n<table>\n<tr><th>증거 유형</th><th>면접에서 말할 방식</th></tr>\n<tr><td>커밋 수</td><td>장기간 유지보수와 반복 개선을 보여주는 보조 증거로만 사용합니다.</td></tr>\n<tr><td>반복 개선 횟수</td><td>기능을 한 번 만들고 끝낸 것이 아니라 오류 상태, 성능, i18n, 권한 흐름을 계속 다듬었다고 설명합니다.</td></tr>\n<tr><td>대체 증거</td><td>정량 성능 수치가 없을 때는 변경 구조, 재현 조건, 리뷰 기록, 테스트 추가, 배포 후 장애 감소 신호를 제시합니다.</td></tr>\n</table>\n</section>\n\n<section id=\"personalfe-ch6\">\n<div class=\"ch-head\"><span class=\"ch-code\">FE-PER-05</span><h2>대체 증거</h2></div>\n<p class=\"lede\">성과 수치가 없을 때는 개선율을 만들지 말고, 작업 규모와 복잡도 증거를 제시합니다. 커밋 수는 성과가 아니라 “얼마나 오래, 얼마나 넓게 만졌는지”를 보여주는 보조 증거입니다.</p>\n<table>\n<tr><th>증거</th><th>어떻게 말할지</th><th>주의점</th></tr>\n<tr><td>커밋 수</td><td>“해당 프로젝트에서 690 작업 커밋 규모로 초기 구축부터 리뉴얼까지 참여했습니다.”</td><td>커밋 수를 생산성이나 품질 수치처럼 말하지 않습니다.</td></tr>\n<tr><td>티켓 수</td><td>“116개 Jira 티켓에 걸쳐 권한, grid, upload, editor, bugfix를 다뤘습니다.”</td><td>티켓 난이도 차이가 있으므로 범위 증거로만 씁니다.</td></tr>\n<tr><td>반복 개선 횟수</td><td>“거래내역 상세와 필터는 60~80회 이상 반복 개선한 핵심 화면이었습니다.”</td><td>정확한 출처가 있는 경우에만 말합니다.</td></tr>\n<tr><td>운영 기간</td><td>“기업 웹사이트는 3.5년 동안 단독 운영하며 성능, SEO/AEO, i18n, 보안을 순차적으로 개선했습니다.”</td><td>운영 기간을 성과로만 말하지 말고 개선 흐름과 연결합니다.</td></tr>\n</table>\n</section>\n\n<section id=\"personalfe-ch7\">\n<div class=\"ch-head\"><span class=\"ch-code\">FE-PER-06</span><h2>심화 드릴 연결</h2></div>\n<p class=\"lede\">심화 기술 질문을 받았을 때는 “알고 있습니다”가 아니라 본인 경험의 증거와 운영 관점으로 연결합니다. 아래 문장은 프론트엔드·JS/TS 원본 문서의 심화 섹션을 개인 답변으로 바꾸는 연결고리입니다.</p>\n<table>\n<tr><th>마커</th><th>압박 질문</th><th>개인화 답변 방향</th></tr>\n<tr><td>REACT CONCURRENT SSR DRILL</td><td>React/Next를 썼다면 Strict Mode, Suspense, streaming SSR 문제도 다뤄봤나요?</td><td>Strict Mode에서 effect cleanup과 중복 요청을 먼저 의심하고, Suspense/Error Boundary는 화면 전체를 막지 않는 경계로 둔다고 답합니다. Next 경험은 SEO/AEO, dynamic import, hydration mismatch 방지처럼 실제 운영 품질과 연결합니다.</td></tr>\n<tr><td>FRONTEND SECURITY CACHE DRILL</td><td>프론트엔드 보안과 성능 캐시는 어디까지 책임질 수 있나요?</td><td>최종 인가는 서버 책임이지만 프론트는 XSS sink 제거, token/cookie trade-off 설명, SameSite 한계 인식, 개인화 응답 cache 정책, preload/resource priority 남용 방지를 책임진다고 답합니다.</td></tr>\n<tr><td>TYPESCRIPT ADVANCED BOUNDARY</td><td>TypeScript를 단순 annotation 이상으로 써본 경험이 있나요?</td><td>외부 API와 form input은 runtime schema validation 또는 adapter에서 검증하고, <code>satisfies</code>, <code>as const</code>, strict flags, branded type은 도메인 계약을 더 선명하게 만드는 도구라고 답합니다.</td></tr>\n</table>\n<h3>짧은 답변 예시</h3>\n<div class=\"serial-card\"><span class=\"sc-label\">90초</span>React/Next 프로젝트에서는 단순히 화면을 구현하는 것보다 서버에서 만든 HTML과 클라이언트 첫 렌더가 어긋나지 않게 하는 점, effect가 재실행되어도 요청과 listener가 중복되지 않게 정리하는 점을 중요하게 봤습니다. 보안은 token 저장 위치를 단정하지 않고 XSS와 CSRF trade-off를 비교하며, 성능은 HTTP cache와 preload가 실제 LCP 후보에 맞는지 확인합니다. TypeScript는 API 응답이 타입과 다를 수 있다는 전제로 adapter와 validation 경계를 둔다고 설명합니다.</div>\n</section>",
};

export default document;
